    async function collectBarcodeIcons() {
        log("[PullLabBarcode] collectBarcodeIcons: starting icon collection");
        var attempts = 0;
        var maxAttempts = BARCODE_RETRY.collectRetries;
        var result = [];

        while (attempts < maxAttempts) {
            if (PULL_LAB_BARCODE_STOPPED) {
                log("[PullLabBarcode] collectBarcodeIcons: stopped during collection");
                return [];
            }

            var presenceCheck = document.querySelectorAll(BARCODE_SELECTORS.presenceCheckAnyIcon);
            log("[PullLabBarcode] collectBarcodeIcons: attempt " + String(attempts + 1) + ", found " + String(presenceCheck.length) + " fa-barcode icons total");

            if (presenceCheck.length === 0) {
                attempts = attempts + 1;
                if (attempts < maxAttempts) {
                    log("[PullLabBarcode] collectBarcodeIcons: no icons found, retrying");
                    await sleep(BARCODE_TIMEOUTS.waitCollectIconsMs / maxAttempts);
                    continue;
                }
                log("[PullLabBarcode] collectBarcodeIcons: no barcode icons found after all retries");
                return [];
            }

            var allIcons = document.querySelectorAll(BARCODE_SELECTORS.barcodeIcon);
            log("[PullLabBarcode] collectBarcodeIcons: found " + String(allIcons.length) + " icons matching barcodeIcon selector");

            result = [];

            var ci = 0;
            while (ci < allIcons.length) {
                if (PULL_LAB_BARCODE_STOPPED) {
                    log("[PullLabBarcode] collectBarcodeIcons: stopped during filtering");
                    return [];
                }

                var icon = allIcons[ci];
                var isVerifiedByClass = icon.classList.contains(BARCODE_SELECTORS.verifiedClass);
                var tooltip = icon.getAttribute(BARCODE_SELECTORS.tooltipAttr) || "";
                var isVerifiedByTooltip = BARCODE_REGEX.verifiedPrefix.test(tooltip);

                if (isVerifiedByClass || isVerifiedByTooltip) {
                    log("[PullLabBarcode] collectBarcodeIcons: icon " + String(ci) + " already verified, skipping");
                    ci = ci + 1;
                    continue;
                }

                var isRequired = BARCODE_REGEX.requiredPrefix.test(tooltip);
                if (!isRequired) {
                    log("[PullLabBarcode] collectBarcodeIcons: icon " + String(ci) + " tooltip does not start with 'Scan Required:', skipping");
                    ci = ci + 1;
                    continue;
                }

                var barcode = extractBarcodeValue(icon);
                if (!barcode) {
                    log("[PullLabBarcode] collectBarcodeIcons: icon " + String(ci) + " has no extractable barcode, skipping");
                    ci = ci + 1;
                    continue;
                }

                var parentRow = icon.closest(BARCODE_SELECTORS.itemRow);
                if (parentRow) {
                    var rowDisplay = parentRow.style.display;
                    if (rowDisplay === "none") {
                        log("[PullLabBarcode] collectBarcodeIcons: icon " + String(ci) + " parent row is hidden (display:none), skipping");
                        ci = ci + 1;
                        continue;
                    }
                }

                var label = tooltip.replace(/^Scan Required:?\s*/i, "").trim();
                if (!label || label.length === 0) {
                    label = barcode;
                }

                var itemName = "";
                if (parentRow) {
                    var textCell = parentRow.querySelector(BARCODE_SELECTORS.itemTextCell);
                    if (textCell) {
                        var textCellClone = textCell.cloneNode(true);
                        var helpTexts = textCellClone.querySelectorAll(BARCODE_SELECTORS.itemHelpText);
                        var hi = 0;
                        while (hi < helpTexts.length) {
                            helpTexts[hi].remove();
                            hi = hi + 1;
                        }
                        itemName = (textCellClone.textContent || "").trim();
                    }
                }
                if (!itemName || itemName.length === 0) {
                    itemName = label;
                }

                var statusKey = barcode + " (#" + String(result.length + 1) + ")";

                result.push({
                    el: icon,
                    barcode: barcode,
                    label: label,
                    itemName: itemName,
                    statusKey: statusKey
                });

                log("[PullLabBarcode] collectBarcodeIcons: added icon " + String(result.length) + " barcode='" + barcode + "' itemName='" + itemName + "'");

                if (PULL_LAB_BARCODE_LEFT_LIST_EL) {
                    var leftRow = document.createElement("div");
                    leftRow.setAttribute("data-barcode-left-item", "");
                    leftRow.style.padding = "6px 10px";
                    leftRow.style.color = "#ddd";
                    leftRow.style.borderBottom = "1px solid #2a2a2a";
                    leftRow.style.overflow = "hidden";
                    var indexSpan = document.createElement("span");
                    indexSpan.style.color = "#666";
                    indexSpan.style.marginRight = "8px";
                    indexSpan.style.fontSize = "12px";
                    indexSpan.textContent = String(result.length) + ".";
                    var nameSpan = document.createElement("span");
                    nameSpan.style.fontSize = "12px";
                    nameSpan.style.fontWeight = "500";
                    nameSpan.textContent = itemName;
                    var barcodeDiv = document.createElement("div");
                    barcodeDiv.style.fontSize = "10px";
                    barcodeDiv.style.color = "#888";
                    barcodeDiv.style.marginTop = "2px";
                    barcodeDiv.style.marginLeft = "20px";
                    barcodeDiv.style.overflow = "hidden";
                    barcodeDiv.style.textOverflow = "ellipsis";
                    barcodeDiv.style.whiteSpace = "nowrap";
                    barcodeDiv.textContent = barcode;
                    leftRow.appendChild(indexSpan);
                    leftRow.appendChild(nameSpan);
                    leftRow.appendChild(barcodeDiv);
                    PULL_LAB_BARCODE_LEFT_LIST_EL.appendChild(leftRow);
                }

                ci = ci + 1;
            }

            if (result.length > 0) {
                break;
            }

            attempts = attempts + 1;
            if (attempts < maxAttempts) {
                log("[PullLabBarcode] collectBarcodeIcons: 0 qualifying icons, retrying");
                await sleep(BARCODE_TIMEOUTS.waitCollectIconsMs / maxAttempts);
            }
        }

        log("[PullLabBarcode] collectBarcodeIcons: collected " + String(result.length) + " icons to process");
        return result;
    }

    async function openBarcodeModalAndFill(iconObj) {
        log("[PullLabBarcode] openBarcodeModalAndFill: starting for barcode='" + iconObj.barcode + "'");
        var attempts = 0;
        var maxAttempts = BARCODE_RETRY.fillConfirmRetries + 1;

        while (attempts < maxAttempts) {
            if (PULL_LAB_BARCODE_STOPPED) {
                log("[PullLabBarcode] openBarcodeModalAndFill: stopped");
                return false;
            }

            attempts = attempts + 1;
            log("[PullLabBarcode] openBarcodeModalAndFill: attempt " + String(attempts) + "/" + String(maxAttempts));

            var existingModal = document.querySelector(BARCODE_SELECTORS.bootboxVisibleModal);
            if (existingModal) {
                log("[PullLabBarcode] openBarcodeModalAndFill: existing modal detected, waiting for it to close");
                await waitUntilHidden(BARCODE_SELECTORS.bootboxVisibleModal, BARCODE_TIMEOUTS.waitModalCloseMs);
                await sleep(BARCODE_TIMEOUTS.waitSettleMs);
            }

            var currentIcon = iconObj.el;
            if (!currentIcon || !document.body.contains(currentIcon)) {
                log("[PullLabBarcode] openBarcodeModalAndFill: icon detached, re-querying by barcode");
                var reQueryIcons = document.querySelectorAll(BARCODE_SELECTORS.barcodeIcon);
                var reFound = false;
                var qi = 0;
                while (qi < reQueryIcons.length) {
                    var qVal = extractBarcodeValue(reQueryIcons[qi]);
                    if (qVal === iconObj.barcode) {
                        iconObj.el = reQueryIcons[qi];
                        currentIcon = reQueryIcons[qi];
                        reFound = true;
                        log("[PullLabBarcode] openBarcodeModalAndFill: re-found icon in DOM");
                        break;
                    }
                    qi = qi + 1;
                }
                if (!reFound) {
                    log("[PullLabBarcode] openBarcodeModalAndFill: icon not found in DOM after re-query");
                    return false;
                }
            }

            var preVerifiedClass = currentIcon.classList.contains(BARCODE_SELECTORS.verifiedClass);
            var preTooltip = currentIcon.getAttribute(BARCODE_SELECTORS.tooltipAttr) || "";
            if (preVerifiedClass || BARCODE_REGEX.verifiedPrefix.test(preTooltip)) {
                log("[PullLabBarcode] openBarcodeModalAndFill: icon already verified before clicking");
                return "already_verified";
            }

            log("[PullLabBarcode] openBarcodeModalAndFill: clicking icon");
            try {
                currentIcon.click();
            } catch (clickErr) {
                log("[PullLabBarcode] openBarcodeModalAndFill: click error " + String(clickErr));
                if (attempts < maxAttempts) {
                    await sleep(BARCODE_TIMEOUTS.waitSettleMs);
                    continue;
                }
                return false;
            }

            log("[PullLabBarcode] openBarcodeModalAndFill: waiting for modal input");
            var modalInput = await waitForSelector(BARCODE_SELECTORS.modalInput, BARCODE_TIMEOUTS.waitModalOpenMs);
            if (!modalInput) {
                log("[PullLabBarcode] openBarcodeModalAndFill: modal input not found after waiting");
                if (attempts < maxAttempts) {
                    await sleep(BARCODE_TIMEOUTS.waitSettleMs);
                    continue;
                }
                return false;
            }

            var visibleModal = document.querySelector(BARCODE_SELECTORS.bootboxVisibleModal);
            if (!visibleModal) {
                log("[PullLabBarcode] openBarcodeModalAndFill: modal container not visible");
                if (attempts < maxAttempts) {
                    await sleep(BARCODE_TIMEOUTS.waitSettleMs);
                    continue;
                }
                return false;
            }

            log("[PullLabBarcode] openBarcodeModalAndFill: filling input with '" + iconObj.barcode + "'");
            try {
                modalInput.focus();
                modalInput.value = iconObj.barcode;
                modalInput.dispatchEvent(new Event("input", { bubbles: true }));
                modalInput.dispatchEvent(new Event("change", { bubbles: true }));
            } catch (fillErr) {
                log("[PullLabBarcode] openBarcodeModalAndFill: fill error " + String(fillErr));
                if (attempts < maxAttempts) {
                    await sleep(BARCODE_TIMEOUTS.waitSettleMs);
                    continue;
                }
                return false;
            }

            await sleep(BARCODE_TIMEOUTS.waitSettleMs);

            log("[PullLabBarcode] openBarcodeModalAndFill: looking for confirm button");
            var confirmBtn = document.querySelector(BARCODE_SELECTORS.modalConfirmPrimary);
            if (!confirmBtn) {
                log("[PullLabBarcode] openBarcodeModalAndFill: primary confirm not found, trying fallback");
                var allPrimaryBtns = document.querySelectorAll(BARCODE_SELECTORS.modalAnyPrimary);
                var bi = 0;
                while (bi < allPrimaryBtns.length) {
                    var btnText = (allPrimaryBtns[bi].textContent || "").trim();
                    if (BARCODE_REGEX.okText.test(btnText)) {
                        confirmBtn = allPrimaryBtns[bi];
                        log("[PullLabBarcode] openBarcodeModalAndFill: found fallback confirm with text '" + btnText + "'");
                        break;
                    }
                    bi = bi + 1;
                }
            }

            if (!confirmBtn) {
                log("[PullLabBarcode] openBarcodeModalAndFill: no confirm button found");
                if (attempts < maxAttempts) {
                    await sleep(BARCODE_TIMEOUTS.waitSettleMs);
                    continue;
                }
                return false;
            }

            log("[PullLabBarcode] openBarcodeModalAndFill: clicking confirm");
            try {
                confirmBtn.click();
            } catch (confirmErr) {
                log("[PullLabBarcode] openBarcodeModalAndFill: confirm click error " + String(confirmErr));
                if (attempts < maxAttempts) {
                    await sleep(BARCODE_TIMEOUTS.waitSettleMs);
                    continue;
                }
                return false;
            }

            log("[PullLabBarcode] openBarcodeModalAndFill: waiting for modal to close");
            var closed = await waitUntilHidden(BARCODE_SELECTORS.bootboxVisibleModal, BARCODE_TIMEOUTS.waitModalCloseMs);
            if (!closed) {
                log("[PullLabBarcode] openBarcodeModalAndFill: modal did not close in time");
                if (attempts < maxAttempts) {
                    continue;
                }
                return false;
            }

            log("[PullLabBarcode] openBarcodeModalAndFill: modal closed, checking for error modal");
            var errorModal = await waitForSelector(BARCODE_SELECTORS.bootboxVisibleModal, 1500);
            if (errorModal) {
                var errorBody = errorModal.querySelector(BARCODE_SELECTORS.bootboxBody);
                var errorText = errorBody ? (errorBody.textContent || "").trim() : "";
                log("[PullLabBarcode] openBarcodeModalAndFill: post-confirm modal detected, text='" + errorText + "'");
                if (errorText.toLowerCase().indexOf("invalid") !== -1) {
                    log("[PullLabBarcode] openBarcodeModalAndFill: invalid barcode error detected");
                    var okBtn = errorModal.querySelector(BARCODE_SELECTORS.bootboxOkBtn);
                    if (!okBtn) {
                        var fallbackBtns = errorModal.querySelectorAll(".modal-footer .btn.btn-primary");
                        var fbi = 0;
                        while (fbi < fallbackBtns.length) {
                            var fbText = (fallbackBtns[fbi].textContent || "").trim();
                            if (BARCODE_REGEX.okText.test(fbText)) {
                                okBtn = fallbackBtns[fbi];
                                break;
                            }
                            fbi = fbi + 1;
                        }
                    }
                    if (okBtn) {
                        log("[PullLabBarcode] openBarcodeModalAndFill: clicking OK to dismiss invalid barcode modal");
                        try {
                            okBtn.click();
                        } catch (okErr) {
                            log("[PullLabBarcode] openBarcodeModalAndFill: OK click error " + String(okErr));
                        }
                        await waitUntilHidden(BARCODE_SELECTORS.bootboxVisibleModal, BARCODE_TIMEOUTS.waitModalCloseMs);
                        await sleep(BARCODE_TIMEOUTS.waitSettleMs);
                    }
                    return "invalid_barcode";
                }
            }

            log("[PullLabBarcode] openBarcodeModalAndFill: modal closed successfully");
            return true;
        }

        log("[PullLabBarcode] openBarcodeModalAndFill: all attempts exhausted");
        return false;
    }

    async function verifyIconUpdated(iconObj) {
        log("[PullLabBarcode] verifyIconUpdated: checking verification for barcode='" + iconObj.barcode + "'");
        var attempts = 0;
        var maxAttempts = BARCODE_RETRY.verifyRetries + 1;

        while (attempts < maxAttempts) {
            if (PULL_LAB_BARCODE_STOPPED) {
                log("[PullLabBarcode] verifyIconUpdated: stopped");
                return false;
            }

            attempts = attempts + 1;
            await sleep(BARCODE_TIMEOUTS.waitVerifyIconMs);

            var currentIcon = iconObj.el;
            if (!currentIcon || !document.body.contains(currentIcon)) {
                log("[PullLabBarcode] verifyIconUpdated: icon detached, re-querying");
                var allIcons = document.querySelectorAll(BARCODE_SELECTORS.barcodeIcon);
                var found = false;
                var qi = 0;
                while (qi < allIcons.length) {
                    var qVal = extractBarcodeValue(allIcons[qi]);
                    if (qVal === iconObj.barcode) {
                        iconObj.el = allIcons[qi];
                        currentIcon = allIcons[qi];
                        found = true;
                        break;
                    }
                    qi = qi + 1;
                }
                if (!found) {
                    var broadIcons = document.querySelectorAll(BARCODE_SELECTORS.presenceCheckAnyIcon);
                    var bqi = 0;
                    while (bqi < broadIcons.length) {
                        var broadVal = extractBarcodeValue(broadIcons[bqi]);
                        if (broadVal === iconObj.barcode) {
                            iconObj.el = broadIcons[bqi];
                            currentIcon = broadIcons[bqi];
                            found = true;
                            break;
                        }
                        bqi = bqi + 1;
                    }
                }
                if (!found) {
                    log("[PullLabBarcode] verifyIconUpdated: icon not found in DOM");
                    if (attempts < maxAttempts) {
                        continue;
                    }
                    return false;
                }
            }

            var hasClass = currentIcon.classList.contains(BARCODE_SELECTORS.verifiedClass);
            var vTooltip = currentIcon.getAttribute(BARCODE_SELECTORS.tooltipAttr) || "";
            var tooltipVerified = BARCODE_REGEX.verifiedPrefix.test(vTooltip);

            if (hasClass || tooltipVerified) {
                log("[PullLabBarcode] verifyIconUpdated: icon verified (class=" + String(hasClass) + ", tooltip=" + String(tooltipVerified) + ")");
                return true;
            }

            log("[PullLabBarcode] verifyIconUpdated: not yet verified, attempt " + String(attempts) + "/" + String(maxAttempts));
        }

        log("[PullLabBarcode] verifyIconUpdated: verification failed after all retries");
        return false;
    }

    async function processIconsSequentially(iconList) {
        log("[PullLabBarcode] processIconsSequentially: starting with " + String(iconList.length) + " icons");

        setAriaBusyOn();
        announceBarcodeAriaLive("Starting barcode processing for " + String(iconList.length) + " items");

        BARCODE_COUNTERS.total = iconList.length;
        BARCODE_COUNTERS.processed = 0;
        BARCODE_COUNTERS.verified = 0;
        BARCODE_COUNTERS.skipped = 0;
        BARCODE_COUNTERS.failures = 0;
        BARCODE_COUNTERS.pending = iconList.length;
        updateBarcodeRightPanelSummary(BARCODE_COUNTERS);

        var startTime = Date.now();
        var idx = 0;

        while (idx < iconList.length) {
            if (PULL_LAB_BARCODE_STOPPED) {
                log("[PullLabBarcode] processIconsSequentially: stopped at index " + String(idx));
                updateBarcodeRightPanelStatus(iconList[idx].statusKey, BARCODE_LABELS.statusStopped);
                break;
            }

            if (Date.now() - startTime > BARCODE_TIMEOUTS.maxTotalDurationMs) {
                log("[PullLabBarcode] processIconsSequentially: max duration exceeded");
                updateBarcodeRightPanelStatus(iconList[idx].statusKey, BARCODE_LABELS.statusStopped, "timeout");
                break;
            }

            var iconObj = iconList[idx];
            log("[PullLabBarcode] processIconsSequentially: processing " + String(idx + 1) + "/" + String(iconList.length) + " barcode='" + iconObj.barcode + "'");

            updateBarcodeRightPanelStatus(iconObj.statusKey, BARCODE_LABELS.statusProcessing);

            var currentIcon = iconObj.el;
            if (currentIcon && document.body.contains(currentIcon)) {
                var alreadyVerifiedClass = currentIcon.classList.contains(BARCODE_SELECTORS.verifiedClass);
                var alreadyTooltip = currentIcon.getAttribute(BARCODE_SELECTORS.tooltipAttr) || "";
                var alreadyVerifiedTooltip = BARCODE_REGEX.verifiedPrefix.test(alreadyTooltip);
                if (alreadyVerifiedClass || alreadyVerifiedTooltip) {
                    log("[PullLabBarcode] processIconsSequentially: icon already verified, skipping");
                    updateBarcodeRightPanelStatus(iconObj.statusKey, BARCODE_LABELS.statusSkippedVerified);
                    BARCODE_COUNTERS.skipped = BARCODE_COUNTERS.skipped + 1;
                    BARCODE_COUNTERS.pending = BARCODE_COUNTERS.pending - 1;
                    updateBarcodeRightPanelSummary(BARCODE_COUNTERS);
                    await barcodeYieldToUI();
                    idx = idx + 1;
                    continue;
                }
            } else {
                log("[PullLabBarcode] processIconsSequentially: icon detached, re-querying");
                var reIcons = document.querySelectorAll(BARCODE_SELECTORS.barcodeIcon);
                var reFound = false;
                var ri = 0;
                while (ri < reIcons.length) {
                    var rVal = extractBarcodeValue(reIcons[ri]);
                    if (rVal === iconObj.barcode) {
                        iconObj.el = reIcons[ri];
                        reFound = true;
                        log("[PullLabBarcode] processIconsSequentially: re-found icon");
                        break;
                    }
                    ri = ri + 1;
                }
                if (!reFound) {
                    log("[PullLabBarcode] processIconsSequentially: icon not found, marking failed");
                    updateBarcodeRightPanelStatus(iconObj.statusKey, BARCODE_LABELS.statusFailed, "detached");
                    BARCODE_COUNTERS.failures = BARCODE_COUNTERS.failures + 1;
                    BARCODE_COUNTERS.pending = BARCODE_COUNTERS.pending - 1;
                    updateBarcodeRightPanelSummary(BARCODE_COUNTERS);
                    await barcodeYieldToUI();
                    idx = idx + 1;
                    continue;
                }
            }

            try {
                var fillResult = await openBarcodeModalAndFill(iconObj);

                if (PULL_LAB_BARCODE_STOPPED) {
                    updateBarcodeRightPanelStatus(iconObj.statusKey, BARCODE_LABELS.statusStopped);
                    break;
                }

                if (fillResult === "already_verified") {
                    log("[PullLabBarcode] processIconsSequentially: icon was already verified");
                    updateBarcodeRightPanelStatus(iconObj.statusKey, BARCODE_LABELS.statusSkippedVerified);
                    BARCODE_COUNTERS.skipped = BARCODE_COUNTERS.skipped + 1;
                    BARCODE_COUNTERS.pending = BARCODE_COUNTERS.pending - 1;
                    updateBarcodeRightPanelSummary(BARCODE_COUNTERS);
                    await barcodeYieldToUI();
                    idx = idx + 1;
                    continue;
                }

                if (fillResult === "invalid_barcode") {
                    log("[PullLabBarcode] processIconsSequentially: invalid barcode for '" + iconObj.barcode + "'");
                    updateBarcodeRightPanelStatus(iconObj.statusKey, BARCODE_LABELS.statusInvalidBarcode);
                    BARCODE_COUNTERS.failures = BARCODE_COUNTERS.failures + 1;
                    BARCODE_COUNTERS.processed = BARCODE_COUNTERS.processed + 1;
                    BARCODE_COUNTERS.pending = BARCODE_COUNTERS.pending - 1;
                    updateBarcodeRightPanelSummary(BARCODE_COUNTERS);
                    await barcodeYieldToUI();
                    idx = idx + 1;
                    continue;
                }

                if (!fillResult) {
                    log("[PullLabBarcode] processIconsSequentially: fill/confirm failed for barcode='" + iconObj.barcode + "'");
                    updateBarcodeRightPanelStatus(iconObj.statusKey, BARCODE_LABELS.statusFailed);
                    BARCODE_COUNTERS.failures = BARCODE_COUNTERS.failures + 1;
                    BARCODE_COUNTERS.processed = BARCODE_COUNTERS.processed + 1;
                    BARCODE_COUNTERS.pending = BARCODE_COUNTERS.pending - 1;
                    updateBarcodeRightPanelSummary(BARCODE_COUNTERS);
                    await barcodeYieldToUI();
                    idx = idx + 1;
                    continue;
                }

                var verified = await verifyIconUpdated(iconObj);

                if (PULL_LAB_BARCODE_STOPPED) {
                    updateBarcodeRightPanelStatus(iconObj.statusKey, BARCODE_LABELS.statusStopped);
                    break;
                }

                if (verified) {
                    log("[PullLabBarcode] processIconsSequentially: verified barcode='" + iconObj.barcode + "'");
                    updateBarcodeRightPanelStatus(iconObj.statusKey, BARCODE_LABELS.statusVerified);
                    BARCODE_COUNTERS.verified = BARCODE_COUNTERS.verified + 1;
                } else {
                    log("[PullLabBarcode] processIconsSequentially: verification failed for barcode='" + iconObj.barcode + "'");
                    updateBarcodeRightPanelStatus(iconObj.statusKey, BARCODE_LABELS.statusFailed, "verify failed");
                    BARCODE_COUNTERS.failures = BARCODE_COUNTERS.failures + 1;
                }

                BARCODE_COUNTERS.processed = BARCODE_COUNTERS.processed + 1;
                BARCODE_COUNTERS.pending = BARCODE_COUNTERS.pending - 1;
                updateBarcodeRightPanelSummary(BARCODE_COUNTERS);
            } catch (procErr) {
                log("[PullLabBarcode] processIconsSequentially: error processing barcode='" + iconObj.barcode + "': " + String(procErr));
                updateBarcodeRightPanelStatus(iconObj.statusKey, BARCODE_LABELS.statusFailed, String(procErr));
                BARCODE_COUNTERS.failures = BARCODE_COUNTERS.failures + 1;
                BARCODE_COUNTERS.processed = BARCODE_COUNTERS.processed + 1;
                BARCODE_COUNTERS.pending = BARCODE_COUNTERS.pending - 1;
                updateBarcodeRightPanelSummary(BARCODE_COUNTERS);
            }

            await barcodeYieldToUI();
            idx = idx + 1;
        }

        setAriaBusyOff();
        PULL_LAB_BARCODE_RUNNING = false;

        var completionMsg = BARCODE_LABELS.done + ": " + String(BARCODE_COUNTERS.verified) + " verified, " + String(BARCODE_COUNTERS.skipped) + " skipped, " + String(BARCODE_COUNTERS.failures) + " failed out of " + String(BARCODE_COUNTERS.total);
        log("[PullLabBarcode] processIconsSequentially: " + completionMsg);
        announceBarcodeAriaLive(completionMsg);
        updateBarcodeRightPanelSummary(BARCODE_COUNTERS);

        if (PULL_LAB_BARCODE_BUTTON_REF) {
            try {
                PULL_LAB_BARCODE_BUTTON_REF.focus();
            } catch (focusErr) {}
        }
    }

    async function pullLabBarcodeInit() {
        log("[PullLabBarcode] pullLabBarcodeInit: starting feature");

        if (PULL_LAB_BARCODE_RUNNING) {
            log("[PullLabBarcode] pullLabBarcodeInit: already running, ignoring");
            return;
        }

        PULL_LAB_BARCODE_STOPPED = false;
        PULL_LAB_BARCODE_RUNNING = true;
        PULL_LAB_BARCODE_STATUS_MAP = {};

        BARCODE_COUNTERS.total = 0;
        BARCODE_COUNTERS.processed = 0;
        BARCODE_COUNTERS.verified = 0;
        BARCODE_COUNTERS.skipped = 0;
        BARCODE_COUNTERS.failures = 0;
        BARCODE_COUNTERS.pending = 0;

        openBarcodeProgressPanel();

        if (PULL_LAB_BARCODE_STOPPED) {
            log("[PullLabBarcode] pullLabBarcodeInit: stopped before collection");
            return;
        }

        announceBarcodeAriaLive(BARCODE_LABELS.scanning);

        var iconList = await collectBarcodeIcons();

        if (PULL_LAB_BARCODE_STOPPED) {
            log("[PullLabBarcode] pullLabBarcodeInit: stopped after collection");
            return;
        }

        if (iconList.length === 0) {
            log("[PullLabBarcode] pullLabBarcodeInit: no icons found");
            if (PULL_LAB_BARCODE_SUMMARY_EL) {
                PULL_LAB_BARCODE_SUMMARY_EL.innerHTML = "";
                var warningSpan = document.createElement("span");
                warningSpan.style.color = "#f0ad4e";
                warningSpan.style.fontWeight = "600";
                warningSpan.textContent = "No barcode icons requiring input were found on this page.";
                PULL_LAB_BARCODE_SUMMARY_EL.appendChild(warningSpan);
            }
            announceBarcodeAriaLive("No barcode icons found");
            PULL_LAB_BARCODE_RUNNING = false;
            setAriaBusyOff();
            return;
        }

        var ri = 0;
        while (ri < iconList.length) {
            updateBarcodeRightPanelStatus(iconList[ri].statusKey, BARCODE_LABELS.statusPending);
            ri = ri + 1;
        }

        await processIconsSequentially(iconList);

        log("[PullLabBarcode] pullLabBarcodeInit: feature completed");
    }

    //==========================
    // PARSE DEVIATION FEATURE
    //==========================
    // This section contains all functions related to the Parse Deviation feature.
    // This feature automates extracting deviation form data from the study data list
    // and formatting it for Excel output.
    //==========================

    // Parse Deviation Feature
    var STORAGE_PARSE_DEVIATION_RUNNING = "activityPlanState.parseDeviation.running";
    var STORAGE_PARSE_DEVIATION_KEYWORDS = "activityPlanState.parseDeviation.keywords";
    var STORAGE_PARSE_DEVIATION_RESULTS = "activityPlanState.parseDeviation.results";
    var STORAGE_PARSE_DEVIATION_TIMESTAMP = "activityPlanState.parseDeviation.timestamp";
    var PARSE_DEVIATION_DATA_LIST_URL = "https://cenexel.clinspark.com/secure/study/data/list";
    var PARSE_DEVIATION_POPUP_REF = null;
    var PARSE_DEVIATION_CANCELED = false;

    function APS_ParseDeviation() {
        log("[ParseDeviation] Starting...");
        PARSE_DEVIATION_CANCELED = false;

        var popupContainer = document.createElement("div");
        popupContainer.style.display = "flex";
        popupContainer.style.flexDirection = "column";
        popupContainer.style.gap = "16px";

        var instructionText = document.createElement("div");
        instructionText.style.fontSize = "14px";
        instructionText.style.color = "#ccc";
        instructionText.style.marginBottom = "8px";
        instructionText.innerHTML = "Enter subject number(s) to search for deviation forms.<br>" +
            "<span style='font-size:12px;color:#888;'>Separate multiple subjects with commas or newlines.</span>";
        popupContainer.appendChild(instructionText);

        var textArea = document.createElement("textarea");
        textArea.style.width = "100%";
        textArea.style.height = "120px";
        textArea.style.background = "#1a1a1a";
        textArea.style.color = "#fff";
        textArea.style.border = "1px solid #444";
        textArea.style.borderRadius = "6px";
        textArea.style.padding = "10px";
        textArea.style.fontSize = "14px";
        textArea.style.fontFamily = "monospace";
        textArea.style.resize = "vertical";
        textArea.style.boxSizing = "border-box";
        textArea.placeholder = "Example:\n4-002, 4-005\n0043\n0000700004";
        popupContainer.appendChild(textArea);

        var buttonsRow = document.createElement("div");
        buttonsRow.style.display = "flex";
        buttonsRow.style.gap = "12px";
        buttonsRow.style.justifyContent = "flex-end";

        var clearAllBtn = document.createElement("button");
        clearAllBtn.textContent = "Clear All";
        clearAllBtn.style.background = "#6c757d";
        clearAllBtn.style.color = "#fff";
        clearAllBtn.style.border = "none";
        clearAllBtn.style.borderRadius = "6px";
        clearAllBtn.style.padding = "10px 20px";
        clearAllBtn.style.cursor = "pointer";
        clearAllBtn.style.fontSize = "14px";
        clearAllBtn.style.fontWeight = "500";
        clearAllBtn.style.transition = "background 0.2s";
        clearAllBtn.onmouseenter = function() { this.style.background = "#5a6268"; };
        clearAllBtn.onmouseleave = function() { this.style.background = "#6c757d"; };

        var confirmBtn = document.createElement("button");
        confirmBtn.textContent = "Confirm";
        confirmBtn.style.background = "#dc3545";
        confirmBtn.style.color = "#fff";
        confirmBtn.style.border = "none";
        confirmBtn.style.borderRadius = "6px";
        confirmBtn.style.padding = "10px 20px";
        confirmBtn.style.cursor = "pointer";
        confirmBtn.style.fontSize = "14px";
        confirmBtn.style.fontWeight = "500";
        confirmBtn.style.transition = "background 0.2s";
        confirmBtn.disabled = true;
        confirmBtn.style.opacity = "0.5";

        function updateConfirmState() {
            var val = textArea.value.trim();
            if (val.length > 0) {
                confirmBtn.disabled = false;
                confirmBtn.style.opacity = "1";
                confirmBtn.style.cursor = "pointer";
            } else {
                confirmBtn.disabled = true;
                confirmBtn.style.opacity = "0.5";
                confirmBtn.style.cursor = "not-allowed";
            }
        }

        textArea.addEventListener("input", updateConfirmState);

        confirmBtn.onmouseenter = function() {
            if (!confirmBtn.disabled) this.style.background = "#c82333";
        };
        confirmBtn.onmouseleave = function() {
            if (!confirmBtn.disabled) this.style.background = "#dc3545";
        };

        buttonsRow.appendChild(clearAllBtn);
        buttonsRow.appendChild(confirmBtn);
        popupContainer.appendChild(buttonsRow);

        var popup = createPopup({
            title: "Parse Deviation",
            content: popupContainer,
            width: "450px",
            height: "auto",
            onClose: function() {
                log("[ParseDeviation] Cancelled by user (close button)");
                PARSE_DEVIATION_CANCELED = true;
            }
        });

        PARSE_DEVIATION_POPUP_REF = popup;

        clearAllBtn.addEventListener("click", function() {
            var confirmClear = confirm("Are you sure you want to clear all input?");
            if (confirmClear) {
                textArea.value = "";
                updateConfirmState();
                log("[ParseDeviation] Input cleared");
            }
        });

        confirmBtn.addEventListener("click", async function() {
            var rawInput = textArea.value;
            var keywords = parseDeviationParseKeywords(rawInput);

            if (keywords.length === 0) {
                log("[ParseDeviation] No valid keywords found");
                return;
            }

            log("[ParseDeviation] Keywords: " + keywords.join(", "));

            var loadingContainer = document.createElement("div");
            loadingContainer.style.display = "flex";
            loadingContainer.style.flexDirection = "column";
            loadingContainer.style.alignItems = "center";
            loadingContainer.style.gap = "20px";
            loadingContainer.style.padding = "40px 20px";

            var spinner = document.createElement("div");
            spinner.style.width = "48px";
            spinner.style.height = "48px";
            spinner.style.border = "4px solid #333";
            spinner.style.borderTop = "4px solid #dc3545";
            spinner.style.borderRadius = "50%";
            spinner.style.animation = "parseDeviationSpin 1s linear infinite";

            var style = document.createElement("style");
            style.textContent = "@keyframes parseDeviationSpin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }";
            document.head.appendChild(style);

            var statusText = document.createElement("div");
            statusText.style.fontSize = "16px";
            statusText.style.fontWeight = "500";
            statusText.style.color = "#f99";
            statusText.textContent = "Navigating to data list...";

            var progressText = document.createElement("div");
            progressText.style.fontSize = "13px";
            progressText.style.color = "#888";
            progressText.textContent = "Please wait...";

            loadingContainer.appendChild(spinner);
            loadingContainer.appendChild(statusText);
            loadingContainer.appendChild(progressText);

            popup.setContent(loadingContainer);

            try {
                localStorage.setItem(STORAGE_PARSE_DEVIATION_KEYWORDS, JSON.stringify(keywords));
                localStorage.setItem(STORAGE_PARSE_DEVIATION_RUNNING, "true");
                localStorage.setItem(STORAGE_PARSE_DEVIATION_TIMESTAMP, String(Date.now()));
            } catch (e) {}

            await sleep(500);

            if (location.href.indexOf("/secure/study/data/list") === -1) {
                statusText.textContent = "Navigating to data list page...";
                progressText.textContent = "Will continue processing after page loads";
                await sleep(500);
                location.href = PARSE_DEVIATION_DATA_LIST_URL;
                return;
            }

            await parseDeviationProcessPage(popup, statusText, progressText, spinner, keywords);
        });
    }

    function parseDeviationParseKeywords(rawInput) {
        var keywords = [];
        var lines = rawInput.split(/[\n\r]+/);
        for (var i = 0; i < lines.length; i++) {
            var parts = lines[i].split(",");
            for (var j = 0; j < parts.length; j++) {
                var kw = parts[j].trim();
                if (kw.length > 0) {
                    keywords.push(kw);
                }
            }
        }
        return keywords;
    }

    async function parseDeviationProcessPage(popup, statusText, progressText, spinner, keywords) {
        log("[ParseDeviation] Processing data list page");

        statusText.textContent = "Selecting deviation forms...";
        progressText.textContent = "Resetting form selections";

        await sleep(500);

        var formSelect = document.querySelector("select[name='formIds']");
        if (!formSelect) {
            log("[ParseDeviation] Form select not found");
            statusText.textContent = "Error: Form select not found";
            statusText.style.color = "#f66";
            spinner.style.display = "none";
            return;
        }

        var allFormOpts = formSelect.querySelectorAll("option");
        for (var fi = 0; fi < allFormOpts.length; fi++) {
            allFormOpts[fi].selected = false;
        }
        var formClearEvt = new Event("change", { bubbles: true });
        formSelect.dispatchEvent(formClearEvt);

        var formSelect2Container = document.querySelector("#s2id_formIds");
        if (formSelect2Container) {
            var formSelect2Choices = formSelect2Container.querySelectorAll(".select2-search-choice");
            for (var fci = 0; fci < formSelect2Choices.length; fci++) {
                var formCloseBtn = formSelect2Choices[fci].querySelector(".select2-search-choice-close");
                if (formCloseBtn) formCloseBtn.click();
            }
        }

        await sleep(300);
        log("[ParseDeviation] Cleared existing form selections");
        progressText.textContent = "Scanning form options";

        var formOptions = formSelect.querySelectorAll("option");
        var deviationKeywords = ["dev", "dpn", "deviation"];
        var selectedFormCount = 0;

        for (var i = 0; i < formOptions.length; i++) {
            var opt = formOptions[i];
            var optText = (opt.textContent || "").toLowerCase();
            for (var k = 0; k < deviationKeywords.length; k++) {
                if (optText.indexOf(deviationKeywords[k]) !== -1) {
                    opt.selected = true;
                    selectedFormCount++;
                    log("[ParseDeviation] Selected form: " + opt.textContent);
                    break;
                }
            }
        }

        if (selectedFormCount === 0) {
            log("[ParseDeviation] No deviation forms found");
            statusText.textContent = "No deviation forms found";
            statusText.style.color = "#f66";
            spinner.style.display = "none";
            progressText.textContent = "Could not find forms matching: dev, DPN, Deviation, PD";
            return;
        }

        var evt = new Event("change", { bubbles: true });
        formSelect.dispatchEvent(evt);

        log("[ParseDeviation] Selected " + selectedFormCount + " deviation form(s)");
        progressText.textContent = "Selected " + selectedFormCount + " form(s)";

        await sleep(500);

        statusText.textContent = "Selecting subjects...";
        progressText.textContent = "Resetting subject selections";

        var subjectSelect = document.querySelector("select[name='subjectIds']");
        if (!subjectSelect) {
            log("[ParseDeviation] Subject select not found");
            statusText.textContent = "Error: Subject select not found";
            statusText.style.color = "#f66";
            spinner.style.display = "none";
            return;
        }

        var allSubjectOpts = subjectSelect.querySelectorAll("option");
        for (var ci = 0; ci < allSubjectOpts.length; ci++) {
            allSubjectOpts[ci].selected = false;
        }
        var clearEvt = new Event("change", { bubbles: true });
        subjectSelect.dispatchEvent(clearEvt);

        var select2Container = document.querySelector("#s2id_subjectIds");
        if (select2Container) {
            var select2Choices = select2Container.querySelectorAll(".select2-search-choice");
            for (var sci = 0; sci < select2Choices.length; sci++) {
                var closeBtn = select2Choices[sci].querySelector(".select2-search-choice-close");
                if (closeBtn) closeBtn.click();
            }
        }

        await sleep(300);
        log("[ParseDeviation] Cleared existing subject selections");
        progressText.textContent = "Matching subjects to keywords";

        var subjectOptions = subjectSelect.querySelectorAll("option");
        var selectedSubjectCount = 0;

        for (var si = 0; si < subjectOptions.length; si++) {
            var subOpt = subjectOptions[si];
            var subText = (subOpt.textContent || "").trim();
            for (var ki = 0; ki < keywords.length; ki++) {
                if (subText.toLowerCase().indexOf(keywords[ki].toLowerCase()) !== -1) {
                    subOpt.selected = true;
                    selectedSubjectCount++;
                    log("[ParseDeviation] Selected subject: " + subText);
                    break;
                }
            }
        }

        if (selectedSubjectCount === 0) {
            log("[ParseDeviation] No matching subjects found");
            statusText.textContent = "No matching subjects found";
            statusText.style.color = "#f66";
            spinner.style.display = "none";
            progressText.textContent = "Keywords: " + keywords.join(", ");
            return;
        }

        var subEvt = new Event("change", { bubbles: true });
        subjectSelect.dispatchEvent(subEvt);

        log("[ParseDeviation] Selected " + selectedSubjectCount + " subject(s)");
        progressText.textContent = "Selected " + selectedSubjectCount + " subject(s)";

        await sleep(500);

        statusText.textContent = "Searching...";
        progressText.textContent = "Clicking search button";

        var searchBtn = document.querySelector("button#dataSearchButton");
        if (!searchBtn) {
            searchBtn = document.querySelector("button[id='dataSearchButton']");
        }
        if (!searchBtn) {
            log("[ParseDeviation] Search button not found");
            statusText.textContent = "Error: Search button not found";
            statusText.style.color = "#f66";
            spinner.style.display = "none";
            return;
        }

        searchBtn.click();
        log("[ParseDeviation] Search button clicked");

        statusText.textContent = "Waiting for results...";
        progressText.textContent = "Loading data...";

        await parseDeviationWaitForResults(5000);

        await sleep(3000);

        statusText.textContent = "Parsing deviation table...";
        progressText.textContent = "Extracting data from rows";

        var allResults = [];
        var pageNum = 1;
        var hasMorePages = true;

        while (hasMorePages) {
            if (PARSE_DEVIATION_CANCELED) {
                log("[ParseDeviation] Process canceled by user");
                return;
            }

            log("[ParseDeviation] Parsing page " + pageNum);
            progressText.textContent = "Parsing page " + pageNum + "...";

            var pageResults = await parseDeviationParseTable();
            allResults = allResults.concat(pageResults);

            log("[ParseDeviation] Found " + pageResults.length + " items on page " + pageNum);

            if (PARSE_DEVIATION_CANCELED) {
                log("[ParseDeviation] Process canceled by user");
                return;
            }

            var nextPage = parseDeviationGetNextPage();
            if (nextPage) {
                nextPage.click();
                await sleep(1500);
                pageNum++;
            } else {
                hasMorePages = false;
            }
        }

        log("[ParseDeviation] Total results: " + allResults.length);

        statusText.textContent = "Fetching subject initials...";
        progressText.textContent = "Processing " + allResults.length + " deviation(s)";

        for (var ri = 0; ri < allResults.length; ri++) {
            if (PARSE_DEVIATION_CANCELED) {
                log("[ParseDeviation] Process canceled by user");
                return;
            }

            if (!allResults[ri].initials || allResults[ri].initials.length === 0) {
                var initials = await parseDeviationFetchInitials(allResults[ri].subjectLink);
                allResults[ri].initials = initials;
            }
        }

        try {
            localStorage.removeItem(STORAGE_PARSE_DEVIATION_RUNNING);
            localStorage.removeItem(STORAGE_PARSE_DEVIATION_KEYWORDS);
        } catch (e) {}

        parseDeviationShowResults(popup, allResults);
    }

    async function parseDeviationWaitForResults(timeoutMs) {
        var start = Date.now();
        while (Date.now() - start < timeoutMs) {
            var tbody = document.querySelector("tbody#studyDataTableBody");
            if (tbody) {
                var rows = tbody.querySelectorAll("tr");
                if (rows.length > 0) {
                    log("[ParseDeviation] Results loaded: " + rows.length + " rows");
                    return true;
                }
            }
            await sleep(300);
        }
        log("[ParseDeviation] Timeout waiting for results");
        return false;
    }

    async function parseDeviationParseTable() {
        var results = [];
        var tbody = document.querySelector("tbody#studyDataTableBody");
        if (!tbody) {
            log("[ParseDeviation] Table body not found");
            return results;
        }

        var rows = tbody.querySelectorAll("tr");
        log("[ParseDeviation] Parsing " + rows.length + " rows");

        var currentForm = null;
        var currentSubject = "";
        var seenLabelsForForm = {};

        for (var i = 0; i < rows.length; i++) {
            var row = rows[i];
            var cells = row.querySelectorAll("td");
            if (cells.length < 5) continue;

            var statusCell = cells[2];
            var canceledIcon = statusCell.querySelector('span.tooltips[data-original-title="Form Canceled"]');
            if (canceledIcon) {
                log("[ParseDeviation] Row " + i + ": Skipping canceled form");
                continue;
            }

            var subjectCell = cells[1];
            var subjectLink = subjectCell.querySelector("a");
            var subjectNumber = "";
            var subjectHref = "";

            if (subjectLink) {
                subjectNumber = (subjectLink.textContent || "").trim();
                subjectHref = subjectLink.getAttribute("href") || "";
            }

            log("[ParseDeviation] Row " + i + ": Subject = '" + subjectNumber + "'");

            var dataCell = cells[4];
            var miniTables = dataCell.querySelectorAll("tbody");
            log("[ParseDeviation] Row " + i + ": Found " + miniTables.length + " mini-tables (item groups)");

            for (var ti = 0; ti < miniTables.length; ti++) {
                var miniRows = miniTables[ti].querySelectorAll("tr");
                var itemGroupData = {};

                for (var mi = 0; mi < miniRows.length; mi++) {
                    var miniCells = miniRows[mi].querySelectorAll("td");
                    if (miniCells.length < 2) continue;

                    var labelCell = miniCells[0];
                    var valueCell = miniCells[1];

                    var label = (labelCell.textContent || "").trim().toLowerCase();
                    var valueEl = valueCell.querySelector("span.novalue");
                    var value = "";
                    if (valueEl) {
                        value = "";
                    } else {
                        value = (valueCell.textContent || "").trim();
                    }

                    itemGroupData[label] = value;
                }

                log("[ParseDeviation] Item group " + ti + " data: " + JSON.stringify(itemGroupData));

                var isNewForm = false;
                if (subjectNumber !== currentSubject) {
                    log("[ParseDeviation] NEW FORM: Subject changed from '" + currentSubject + "' to '" + subjectNumber + "'");
                    isNewForm = true;
                } else {
                    for (var key in itemGroupData) {
                        if (key.indexOf("date of deviation") !== -1 && seenLabelsForForm[key]) {
                            var newDateVal = itemGroupData[key];
                            log("[ParseDeviation] Checking date of deviation: '" + newDateVal + "' (seen before: " + seenLabelsForForm[key] + ")");
                            if (newDateVal && newDateVal.length > 0 && newDateVal !== "-") {
                                log("[ParseDeviation] NEW FORM: Date of deviation has non-empty value");
                                isNewForm = true;
                                break;
                            }
                        }
                    }
                }

                if (isNewForm && currentForm) {
                    log("[ParseDeviation] Pushing completed form to results");
                    currentForm.actionTakenCombined = currentForm.actionTaken.join("; ");
                    delete currentForm.actionTaken;
                    results.push(currentForm);
                    currentForm = null;
                    seenLabelsForForm = {};
                }

                if (!currentForm) {
                    log("[ParseDeviation] Creating new form for subject '" + subjectNumber + "'");
                    currentForm = {
                        subjectNumber: subjectNumber,
                        subjectLink: subjectHref,
                        dateOfDeviation: "",
                        studyVisitDay: "",
                        dateDiscovered: "",
                        deviationExplanation: "",
                        severity: "",
                        reportable: "",
                        initials: "",
                        category: "",
                        actionTaken: []
                    };
                    currentSubject = subjectNumber;
                }

                for (var key in itemGroupData) {
                    var val = itemGroupData[key];
                    if (val && val.length > 0 && val !== "-") {
                        seenLabelsForForm[key] = true;

                        if (key.indexOf("date of deviation") !== -1) {
                            if (!currentForm.dateOfDeviation || currentForm.dateOfDeviation === "-") currentForm.dateOfDeviation = val;
                        } else if (key.indexOf("study visit day") !== -1) {
                            if (!currentForm.studyVisitDay || currentForm.studyVisitDay === "-") currentForm.studyVisitDay = val;
                        } else if (key.indexOf("date discovered") !== -1) {
                            if (!currentForm.dateDiscovered || currentForm.dateDiscovered === "-") currentForm.dateDiscovered = val;
                        } else if (key.indexOf("description") !== -1 || key.indexOf("explanation") !== -1) {
                            if (!currentForm.deviationExplanation || currentForm.deviationExplanation === "-") currentForm.deviationExplanation = val;
                        } else if (key.indexOf("severity") !== -1) {
                            if (!currentForm.severity || currentForm.severity === "-") currentForm.severity = val;
                        } else if (key.indexOf("reportable") !== -1) {
                            if (!currentForm.reportable || currentForm.reportable === "-") currentForm.reportable = val;
                        } else if (key.indexOf("initial") !== -1) {
                            if (!currentForm.initials || currentForm.initials === "-") currentForm.initials = val;
                        } else if (key.indexOf("category") !== -1) {
                            if (!currentForm.category || currentForm.category === "-") currentForm.category = val;
                        } else if (key.indexOf("corrective") !== -1 || key.indexOf("preventative") !== -1 || key.indexOf("preventive") !== -1) {
                            currentForm.actionTaken.push(val);
                        }
                    }
                }
                log("[ParseDeviation] Current form state: " + JSON.stringify(currentForm));
            }
        }

        if (currentForm) {
            log("[ParseDeviation] Pushing final form to results");
            currentForm.actionTakenCombined = currentForm.actionTaken.join("; ");
            delete currentForm.actionTaken;
            results.push(currentForm);
        }

        log("[ParseDeviation] Total forms created: " + results.length);
        return results;
    }

    function parseDeviationGetNextPage() {
        var pager = document.querySelector("p#pagerButtons");
        if (!pager) {
            var pagerAlt = document.querySelector("#pagerButtons");
            if (pagerAlt) pager = pagerAlt;
        }
        if (!pager) return null;

        var currentDisabled = pager.querySelector("li.disabled a, li.active a");
        if (!currentDisabled) return null;

        var currentLi = currentDisabled.closest("li");
        if (!currentLi) return null;

        var nextLi = currentLi.nextElementSibling;
        while (nextLi) {
            var dataLp = nextLi.getAttribute("data-lp");
            if (dataLp && !nextLi.classList.contains("disabled")) {
                var nextLink = nextLi.querySelector("a");
                if (nextLink) {
                    return nextLink;
                }
            }
            nextLi = nextLi.nextElementSibling;
        }

        return null;
    }

    async function parseDeviationFetchInitials(subjectHref) {
        if (!subjectHref || subjectHref.length === 0) {
            return "";
        }

        try {
            var fullUrl = location.origin + subjectHref;
            log("[ParseDeviation] Fetching initials from: " + fullUrl);

            return new Promise(function(resolve) {
                var iframe = document.createElement("iframe");
                iframe.style.position = "fixed";
                iframe.style.top = "-9999px";
                iframe.style.left = "-9999px";
                iframe.style.width = "1px";
                iframe.style.height = "1px";
                iframe.style.visibility = "hidden";

                var timeoutId = setTimeout(function() {
                    if (iframe.parentNode) iframe.parentNode.removeChild(iframe);
                    resolve("");
                }, 10000);

                iframe.onload = function() {
                    try {
                        var iframeDoc = iframe.contentDocument || iframe.contentWindow.document;
                        var volunteerLink = iframeDoc.querySelector("a[href*='/secure/volunteers/manage/show/']");
                        if (volunteerLink) {
                            var linkText = (volunteerLink.textContent || "").trim();
                            var parts = linkText.split(",");
                            if (parts.length >= 3) {
                                var initials = parts[2].trim();
                                log("[ParseDeviation] Found initials: " + initials);
                                clearTimeout(timeoutId);
                                if (iframe.parentNode) iframe.parentNode.removeChild(iframe);
                                resolve(initials);
                                return;
                            }
                        }
                        clearTimeout(timeoutId);
                        if (iframe.parentNode) iframe.parentNode.removeChild(iframe);
                        resolve("");
                    } catch (e) {
                        clearTimeout(timeoutId);
                        if (iframe.parentNode) iframe.parentNode.removeChild(iframe);
                        resolve("");
                    }
                };

                iframe.onerror = function() {
                    clearTimeout(timeoutId);
                    if (iframe.parentNode) iframe.parentNode.removeChild(iframe);
                    resolve("");
                };

                document.body.appendChild(iframe);
                iframe.src = fullUrl;
            });
        } catch (e) {
            log("[ParseDeviation] Error fetching initials: " + e);
            return "";
        }
    }

    function parseDeviationFormatDate(dateStr) {
        if (!dateStr || dateStr.length === 0) return "";

        var months = {
            "jan": 1, "feb": 2, "mar": 3, "apr": 4, "may": 5, "jun": 6,
            "jul": 7, "aug": 8, "sep": 9, "oct": 10, "nov": 11, "dec": 12
        };

        var match = dateStr.match(/(\d{1,2})\s*([A-Za-z]{3})\s*(\d{4})/);
        if (match) {
            var day = parseInt(match[1], 10);
            var monthStr = match[2].toLowerCase();
            var year = parseInt(match[3], 10);
            var month = months[monthStr] || 1;
            return month + "/" + day + "/" + year;
        }

        return dateStr;
    }

    function parseDeviationFormatVisitDay(visitDayStr) {
        if (!visitDayStr || visitDayStr.length === 0) return "";

        var match = visitDayStr.match(/[Dd]ay\s*(\d+)/i);
        if (match) {
            return "D" + match[1];
        }

        var numMatch = visitDayStr.match(/^(\d+)$/);
        if (numMatch) {
            return "D" + numMatch[1];
        }

        return visitDayStr;
    }

    function parseDeviationSanitizeValue(val) {
        if (!val) return "";
        return String(val).replace(/[\t\r\n]+/g, " ").trim();
    }

    function parseDeviationFormatSubjectNumber(subjectStr) {
        if (!subjectStr) return "";
        var parts = subjectStr.split("/");
        if (parts.length >= 2) {
            var middle = parts[1].trim();
            if (/[a-zA-Z]/.test(middle)) {
                var allNumbers = middle.match(/\d+(?:-\d+)?/g);
                if (allNumbers) {
                    for (var i = 0; i < allNumbers.length; i++) {
                        var numWithoutDash = allNumbers[i].replace(/-/g, "");
                        if (numWithoutDash.length > 3) {
                            return allNumbers[i];
                        }
                    }
                }
                return parts[0].trim();
            }
            return middle;
        }
        return subjectStr.trim();
    }

    function parseDeviationFormatActionTaken(actionStr) {
        if (!actionStr) return "";
        return actionStr.replace(/;\s*/g, " ");
    }

    function parseDeviationFormatSeverity(severityStr) {
        if (!severityStr) return "";
        if (severityStr.toLowerCase().indexOf("minor") !== -1) {
            return "Minor";
        }
        return severityStr;
    }

    function parseDeviationFormatReportable(reportableStr) {
        if (!reportableStr) return "";
        var lower = reportableStr.toLowerCase();
        if (lower.indexOf("not") !== -1 || lower.indexOf("no") !== -1) {
            return "No";
        }
        return "Yes";
    }

    function parseDeviationFormatRow(item) {
        var TAB = "\t";

        var colA = "=IFERROR(INDEX(A:A,ROW()-1)+1,1)";
        var colB = "ACT";
        var colC = "";
        var colD = "";
        var colE = parseDeviationSanitizeValue(parseDeviationFormatSubjectNumber(item.subjectNumber));
        var colF = parseDeviationSanitizeValue(parseDeviationFormatVisitDay(item.studyVisitDay));
        var colG = "";
        var colH = parseDeviationSanitizeValue(parseDeviationFormatDate(item.dateOfDeviation));
        var colI = parseDeviationSanitizeValue(parseDeviationFormatDate(item.dateDiscovered));
        var colJ = parseDeviationSanitizeValue(item.initials);
        var colK = parseDeviationSanitizeValue(item.deviationExplanation);
        var colL = parseDeviationSanitizeValue(parseDeviationFormatActionTaken(item.actionTakenCombined));
        var colM = "";
        var colN = parseDeviationSanitizeValue(item.category);
        var colO = "";
        var colP = "";
        var colQ = "";
        var colR = "";
        var colS = "";
        var colT = parseDeviationSanitizeValue(parseDeviationFormatSeverity(item.severity));
        var colU = parseDeviationSanitizeValue(parseDeviationFormatReportable(item.reportable));

        var row = colA + TAB + colB + TAB + colC + TAB + colD + TAB +
            colE + TAB + colF + TAB + colG + TAB + colH + TAB +
            colI + TAB + colJ + TAB + colK + TAB + colL + TAB +
            colM + TAB + colN + TAB + colO + TAB + colP + TAB +
            colQ + TAB + colR + TAB + colS + TAB + colT + TAB + colU;

        return row;
    }

    function parseDeviationShowResults(popup, results) {
        log("[ParseDeviation] Displaying " + results.length + " results");

        var container = document.createElement("div");
        container.style.display = "flex";
        container.style.flexDirection = "column";
        container.style.gap = "12px";
        container.style.maxHeight = "500px";
        container.style.overflowY = "auto";

        var headerDiv = document.createElement("div");
        headerDiv.style.display = "flex";
        headerDiv.style.justifyContent = "space-between";
        headerDiv.style.alignItems = "center";
        headerDiv.style.marginBottom = "8px";
        headerDiv.style.padding = "8px";
        headerDiv.style.background = "#1a1a1a";
        headerDiv.style.borderRadius = "6px";

        var countText = document.createElement("div");
        countText.style.fontSize = "14px";
        countText.style.fontWeight = "600";
        countText.textContent = "Found " + results.length + " deviation(s)";
        headerDiv.appendChild(countText);

        var copyAllBtn = document.createElement("button");
        copyAllBtn.textContent = "Copy All";
        copyAllBtn.style.background = "#dc3545";
        copyAllBtn.style.color = "#fff";
        copyAllBtn.style.border = "none";
        copyAllBtn.style.borderRadius = "4px";
        copyAllBtn.style.padding = "6px 12px";
        copyAllBtn.style.cursor = "pointer";
        copyAllBtn.style.fontSize = "12px";
        copyAllBtn.style.fontWeight = "500";
        copyAllBtn.onmouseenter = function() { this.style.background = "#c82333"; };
        copyAllBtn.onmouseleave = function() { this.style.background = "#dc3545"; };
        copyAllBtn.addEventListener("click", function() {
            var allRows = [];
            for (var i = 0; i < results.length; i++) {
                allRows.push(parseDeviationFormatRow(results[i]));
            }
            var allText = allRows.join("\n");
            navigator.clipboard.writeText(allText).then(function() {
                copyAllBtn.textContent = "Copied!";
                setTimeout(function() { copyAllBtn.textContent = "Copy All"; }, 1500);
            });
        });
        headerDiv.appendChild(copyAllBtn);

        container.appendChild(headerDiv);

        if (results.length === 0) {
            var noResults = document.createElement("div");
            noResults.style.textAlign = "center";
            noResults.style.padding = "40px";
            noResults.style.color = "#888";
            noResults.textContent = "No deviation data found.";
            container.appendChild(noResults);
        } else {
            for (var i = 0; i < results.length; i++) {
                var item = results[i];
                var rowDiv = document.createElement("div");
                rowDiv.style.display = "flex";
                rowDiv.style.flexDirection = "column";
                rowDiv.style.gap = "8px";
                rowDiv.style.padding = "12px";
                rowDiv.style.background = "#1a1a1a";
                rowDiv.style.borderRadius = "6px";
                rowDiv.style.border = "1px solid #333";

                var rowHeader = document.createElement("div");
                rowHeader.style.display = "flex";
                rowHeader.style.justifyContent = "space-between";
                rowHeader.style.alignItems = "center";

                var subjectInfo = document.createElement("div");
                subjectInfo.style.fontWeight = "600";
                subjectInfo.style.fontSize = "14px";
                subjectInfo.textContent = item.subjectNumber || "Unknown Subject";
                rowHeader.appendChild(subjectInfo);

                var copyBtn = document.createElement("button");
                copyBtn.textContent = "Copy";
                copyBtn.style.background = "#28a745";
                copyBtn.style.color = "#fff";
                copyBtn.style.border = "none";
                copyBtn.style.borderRadius = "4px";
                copyBtn.style.padding = "4px 10px";
                copyBtn.style.cursor = "pointer";
                copyBtn.style.fontSize = "12px";
                copyBtn.style.fontWeight = "500";
                copyBtn.onmouseenter = function() { this.style.background = "#218838"; };
                copyBtn.onmouseleave = function() { this.style.background = "#28a745"; };

                (function(btn, itemData) {
                    btn.addEventListener("click", function() {
                        var formattedRow = parseDeviationFormatRow(itemData);
                        navigator.clipboard.writeText(formattedRow).then(function() {
                            btn.textContent = "Copied!";
                            setTimeout(function() { btn.textContent = "Copy"; }, 1500);
                        });
                    });
                })(copyBtn, item);

                rowHeader.appendChild(copyBtn);
                rowDiv.appendChild(rowHeader);

                var detailsGrid = document.createElement("div");
                detailsGrid.style.display = "grid";
                detailsGrid.style.gridTemplateColumns = "1fr 1fr";
                detailsGrid.style.gap = "6px";
                detailsGrid.style.fontSize = "12px";

                function addDetail(label, value) {
                    var detailItem = document.createElement("div");
                    detailItem.innerHTML = "<span style='color:#888;'>" + label + ":</span> " +
                        "<span style='color:#fff;'>" + (value || "-") + "</span>";
                    detailsGrid.appendChild(detailItem);
                }

                addDetail("Visit Day", parseDeviationFormatVisitDay(item.studyVisitDay));
                addDetail("Date of Deviation", parseDeviationFormatDate(item.dateOfDeviation));
                addDetail("Date Discovered", parseDeviationFormatDate(item.dateDiscovered));
                addDetail("Initials", item.initials);
                addDetail("Severity", item.severity);
                addDetail("Reportable", item.reportable);

                rowDiv.appendChild(detailsGrid);

                if (item.deviationExplanation) {
                    var explanationDiv = document.createElement("div");
                    explanationDiv.style.fontSize = "12px";
                    explanationDiv.style.color = "#ccc";
                    explanationDiv.style.marginTop = "4px";
                    explanationDiv.style.padding = "8px";
                    explanationDiv.style.background = "#222";
                    explanationDiv.style.borderRadius = "4px";
                    explanationDiv.style.maxHeight = "60px";
                    explanationDiv.style.overflowY = "auto";
                    explanationDiv.textContent = item.deviationExplanation;
                    rowDiv.appendChild(explanationDiv);
                }

                container.appendChild(rowDiv);
            }
        }

        popup.setContent(container);
        popup.element.style.width = "600px";
        popup.element.style.height = "auto";
        popup.element.style.maxHeight = "80%";

        var rect = popup.element.getBoundingClientRect();
        popup.element.style.left = (window.innerWidth / 2) + "px";
        popup.element.style.top = (window.innerHeight / 2) + "px";
        popup.element.style.transform = "translate(-50%, -50%)";
    }

    function parseDeviationCheckOnPageLoad() {
        var isRunning = false;
        try {
            isRunning = localStorage.getItem(STORAGE_PARSE_DEVIATION_RUNNING) === "true";
        } catch (e) {}

        if (!isRunning) return;

        if (location.href.indexOf("/secure/study/data/list") === -1) return;

        // Check timestamp to prevent auto-run on casual navigation
        var timestamp = 0;
        try {
            var tsRaw = localStorage.getItem(STORAGE_PARSE_DEVIATION_TIMESTAMP);
            if (tsRaw) timestamp = parseInt(tsRaw, 10);
        } catch (e) {}

        var now = Date.now();
        var elapsed = now - timestamp;
        var maxAge = 10000; // 10 seconds

        if (elapsed > maxAge || timestamp === 0) {
            log("[ParseDeviation] Timestamp expired or missing (elapsed=" + elapsed + "ms), skipping auto-resume");
            try {
                localStorage.removeItem(STORAGE_PARSE_DEVIATION_RUNNING);
                localStorage.removeItem(STORAGE_PARSE_DEVIATION_KEYWORDS);
                localStorage.removeItem(STORAGE_PARSE_DEVIATION_TIMESTAMP);
            } catch (e) {}
            return;
        }

        var keywords = [];
        try {
            var raw = localStorage.getItem(STORAGE_PARSE_DEVIATION_KEYWORDS);
            if (raw) keywords = JSON.parse(raw);
        } catch (e) {}

        if (keywords.length === 0) {
            try {
                localStorage.removeItem(STORAGE_PARSE_DEVIATION_RUNNING);
                localStorage.removeItem(STORAGE_PARSE_DEVIATION_TIMESTAMP);
            } catch (e) {}
            return;
        }
        log("[ParseDeviation] Resuming after page load with keywords: " + keywords.join(", "));

        var popupContainer = document.createElement("div");
        popupContainer.style.display = "flex";
        popupContainer.style.flexDirection = "column";
        popupContainer.style.alignItems = "center";
        popupContainer.style.gap = "20px";
        popupContainer.style.padding = "40px 20px";

        var spinner = document.createElement("div");
        spinner.style.width = "48px";
        spinner.style.height = "48px";
        spinner.style.border = "4px solid #333";
        spinner.style.borderTop = "4px solid #dc3545";
        spinner.style.borderRadius = "50%";
        spinner.style.animation = "parseDeviationSpin 1s linear infinite";

        var style = document.createElement("style");
        style.textContent = "@keyframes parseDeviationSpin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }";
        document.head.appendChild(style);

        var statusText = document.createElement("div");
        statusText.style.fontSize = "16px";
        statusText.style.fontWeight = "500";
        statusText.style.color = "#f99";
        statusText.textContent = "Resuming Parse Deviation...";

        var progressText = document.createElement("div");
        progressText.style.fontSize = "13px";
        progressText.style.color = "#888";
        progressText.textContent = "Please wait...";

        popupContainer.appendChild(spinner);
        popupContainer.appendChild(statusText);
        popupContainer.appendChild(progressText);

        PARSE_DEVIATION_CANCELED = false;

        var popup = createPopup({
            title: "Parse Deviation",
            content: popupContainer,
            width: "450px",
            height: "auto",
            onClose: function() {
                log("[ParseDeviation] Cancelled by user (close button)");
                PARSE_DEVIATION_CANCELED = true;
            }
        });

        PARSE_DEVIATION_POPUP_REF = popup;

        setTimeout(async function() {
            await parseDeviationProcessPage(popup, statusText, progressText, spinner, keywords);
        }, 1000);
    }

    //=========================
    // SETTING FEATURE
    //=========================
    // This section contains functions for setting up the extension.
    // It includes functions for loading and saving settings, as well as
    // functions for updating the UI based on the current settings.
    //=========================
    var STORAGE_BUTTON_VISIBILITY = "activityPlanState.buttonVisibility";
    var STORAGE_BUTTON_LAYOUT = "activityPlanState.buttonLayout";
    var SETTINGS_MODAL_OPEN = false;

    var PANEL_BUTTON_DEFS = [
        { id: "Pull Barcode", label: "Pull Barcode" },
        { id: "Pull Lab Barcode", label: "Pull Lab Barcode" },
        { id: "PLAP Builder", label: "PLAP Builder" },
        { id: "Import From Library", label: "Import From Library"},
        { id: "Archive/Update Forms", label: "Archive/Update Forms" },
        { id: "Copy Activity Forms", label: "Copy Activity Forms" },
        { id: "Search Methods", label: "Search Methods" },
        { id: "Parse Deviation", label: "Parse Deviation" },
        { id: "Import I/E", label: "Import I/E" },
        { id: "Find Adverse Event", label: "Find Adverse Event" },
        { id: "Find Form", label: "Find Form" },
        { id: "Find Study Events", label: "Find Study Events" },
        { id: "Set Visibility Condition", label: "Set Visibility Condition" },
        { id: "Item Method Forms", label: "Item Method Forms" },
        { id: "Cohort Eligibility", label: "Cohort Eligibility" },
        { id: "Subject Eligibility", label: "Subject Eligibility" },
        { id: "Parse Study Event", label: "Parse Study Event" },
        { id: "Edit Study Events List", label: "Edit Study Events List" },
        { id: "Pause", label: "Pause" },
        { id: "Clear Logs", label: "Clear Logs" },
        { id: "Hide Logs", label: "Hide Logs" }
    ];

    function getPanelHotkey() {
        try {
            var saved = localStorage.getItem(STORAGE_PANEL_HOTKEY);
            if (saved) {
                return saved;
            }
        } catch (err) {
            log("Error reading hotkey from localStorage: " + String(err));
        }
        return "F2";
    }

    function setPanelHotkey(hotkey) {
        try {
            localStorage.setItem(STORAGE_PANEL_HOTKEY, hotkey);
            return true;
        } catch (err) {
            log("Error saving hotkey to localStorage: " + String(err));
            return false;
        }
    }

    function getButtonVisibility() {
        try {
            var raw = localStorage.getItem(STORAGE_BUTTON_VISIBILITY);
            if (raw) {
                return JSON.parse(raw);
            }
        } catch (e) {}
        return null;
    }

    function setButtonVisibility(visibilityMap) {
        try {
            localStorage.setItem(STORAGE_BUTTON_VISIBILITY, JSON.stringify(visibilityMap));
        } catch (e) {}
    }

    function loadButtonLayout() {
        try {
            var raw = localStorage.getItem(STORAGE_BUTTON_LAYOUT);
            if (!raw) return null;
            var parsed = JSON.parse(raw);
            if (!Array.isArray(parsed)) return null;
            return parsed;
        } catch (e) {
            return null;
        }
    }

    function saveButtonLayout(layout) {
        try {
            localStorage.setItem(STORAGE_BUTTON_LAYOUT, JSON.stringify(layout));
        } catch (e) {}
    }

    function getEffectiveButtonLayout() {
        var saved = loadButtonLayout();
        var defaultLayout = [];
        for (var di = 0; di < PANEL_BUTTON_DEFS.length; di++) {
            defaultLayout.push({ id: PANEL_BUTTON_DEFS[di].id, position: di, visible: true });
        }
        if (!saved || !Array.isArray(saved)) {
            // Migrate from old visibility map if it exists
            var oldVis = getButtonVisibility();
            if (oldVis) {
                for (var mi = 0; mi < defaultLayout.length; mi++) {
                    if (oldVis.hasOwnProperty(defaultLayout[mi].id)) {
                        defaultLayout[mi].visible = !!oldVis[defaultLayout[mi].id];
                    }
                }
            }
            return defaultLayout;
        }
        var savedIds = {};
        for (var s = 0; s < saved.length; s++) { savedIds[saved[s].id] = true; }
        var maxPos = -1;
        for (var mm = 0; mm < saved.length; mm++) {
            if (saved[mm].position > maxPos) maxPos = saved[mm].position;
        }
        var currentIds = {};
        for (var c = 0; c < PANEL_BUTTON_DEFS.length; c++) { currentIds[PANEL_BUTTON_DEFS[c].id] = true; }
        for (var n = 0; n < PANEL_BUTTON_DEFS.length; n++) {
            if (!savedIds[PANEL_BUTTON_DEFS[n].id]) {
                maxPos++;
                saved.push({ id: PANEL_BUTTON_DEFS[n].id, position: maxPos, visible: true });
            }
        }
        return saved.filter(function(e) { return currentIds[e.id]; });
    }

    function buildPanelDefMap() {
        var map = {};
        for (var i = 0; i < PANEL_BUTTON_DEFS.length; i++) {
            map[PANEL_BUTTON_DEFS[i].id] = PANEL_BUTTON_DEFS[i];
        }
        return map;
    }

    function isButtonVisible(label) {
        var layout = getEffectiveButtonLayout();
        for (var i = 0; i < layout.length; i++) {
            if (layout[i].id === label) {
                return layout[i].visible;
            }
        }
        return true;
    }

    function openSettingsPopup() {
        if (SETTINGS_MODAL_OPEN) return null;
        SETTINGS_MODAL_OPEN = true;

        var pendingLayout = JSON.parse(JSON.stringify(getEffectiveButtonLayout()));
        var originalLayout = JSON.parse(JSON.stringify(pendingLayout));
        var pendingTheme = getThemeMode();
        var originalTheme = pendingTheme;
        var pendingHotkey = getPanelHotkey();
        var originalHotkey = pendingHotkey;
        var cfgHasDirty = false;

        // --- Theme-aware color palette ---
        var _g = (getThemeMode() === THEME_MODE_GLASS);
        var tc = {
            containerBg: _g ? "linear-gradient(135deg,#667eea 0%,#764ba2 100%)" : "#1a1a1a",
            headerBg: _g ? "rgba(255,255,255,0.1)" : "#222",
            headerBorder: _g ? "rgba(255,255,255,0.2)" : "#333",
            sectionBorder: _g ? "rgba(255,255,255,0.15)" : "#2a2a2a",
            closeBg: _g ? "rgba(255,255,255,0.2)" : "rgba(255,255,255,0.1)",
            textSec: _g ? "rgba(255,255,255,0.9)" : "#ccc",
            textMuted: _g ? "rgba(255,255,255,0.5)" : "#777",
            textHint: _g ? "rgba(255,255,255,0.45)" : "#666",
            inputBg: _g ? "rgba(15,10,40,0.7)" : "#2a2a2a",
            inputBorder: _g ? "rgba(255,255,255,0.3)" : "#444",
            inputText: _g ? "#e0e0ff" : "#fff",
            inputFocus: _g ? "rgba(255,255,255,0.6)" : "#5b43c7",
            gridBg: _g ? "rgba(0,0,0,0.15)" : "rgba(0,0,0,0.3)",
            cellBg: _g ? "rgba(255,255,255,0.07)" : "rgba(255,255,255,0.04)",
            cellHover: _g ? "rgba(255,255,255,0.14)" : "rgba(255,255,255,0.08)",
            cellDrag: _g ? "rgba(118,75,162,0.45)" : "rgba(91,67,199,0.3)",
            cellDragBorder: _g ? "rgba(180,140,255,0.5)" : "rgba(91,67,199,0.5)",
            cellFaded: _g ? "rgba(255,255,255,0.03)" : "rgba(255,255,255,0.02)",
            tBtnActiveBg: _g ? "rgba(255,255,255,0.25)" : "#5b43c7",
            tBtnActiveBorder: _g ? "rgba(255,255,255,0.5)" : "rgba(91,67,199,0.8)",
            tBtnInactiveBg: _g ? "rgba(0,0,0,0.15)" : "#333",
            tBtnInactiveBorder: _g ? "rgba(255,255,255,0.2)" : "#444",
            tBtnHover: _g ? "rgba(0,0,0,0.25)" : "#444",
            cancelBg: _g ? "rgba(255,255,255,0.15)" : "rgba(255,255,255,0.1)",
            cancelBorder: _g ? "rgba(255,255,255,0.3)" : "#444",
            cancelHover: _g ? "rgba(255,255,255,0.25)" : "rgba(255,255,255,0.15)"
        };

        // --- Overlay ---
        var overlay = document.createElement("div");
        overlay.style.cssText = "position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.6);z-index:30000;display:flex;align-items:center;justify-content:center;font-family:'Segoe UI',Tahoma,Geneva,Verdana,sans-serif;";

        // --- Container ---
        var container = document.createElement("div");
        container.setAttribute("role", "dialog");
        container.setAttribute("aria-modal", "true");
        container.setAttribute("aria-labelledby", "cfg-modal-title");
        container.style.cssText = "background:" + tc.containerBg + ";border-radius:12px;padding:0;width:520px;max-width:94%;box-shadow:0 15px 35px rgba(0,0,0,0.4);position:relative;display:flex;flex-direction:column;max-height:92vh;";

        // --- Header ---
        var modalHeader = document.createElement("div");
        modalHeader.style.cssText = "display:flex;justify-content:space-between;align-items:center;padding:14px 16px;border-bottom:1px solid " + tc.headerBorder + ";background:" + tc.headerBg + ";border-radius:12px 12px 0 0;flex-shrink:0;";

        var modalTitle = document.createElement("h3");
        modalTitle.id = "cfg-modal-title";
        modalTitle.textContent = "Settings";
        modalTitle.style.cssText = "margin:0;color:white;font-size:16px;font-weight:600;";

        var modalClose = document.createElement("button");
        modalClose.innerHTML = "\u2715";
        modalClose.setAttribute("aria-label", "Close settings");
        modalClose.setAttribute("type", "button");
        modalClose.style.cssText = "background:" + tc.closeBg + ";border:none;color:white;width:28px;height:28px;border-radius:50%;cursor:pointer;font-size:14px;display:flex;align-items:center;justify-content:center;transition:all 0.3s ease;";
        modalClose.onmouseover = function() { modalClose.style.background = "rgba(255,67,54,0.8)"; };
        modalClose.onmouseout = function() { modalClose.style.background = tc.closeBg; };

        modalHeader.appendChild(modalTitle);
        modalHeader.appendChild(modalClose);

        // --- Body (scrollable) ---
        var modalBody = document.createElement("div");
        modalBody.style.cssText = "padding:16px;overflow-y:auto;flex:1;";

        // === HOTKEY SECTION ===
        var hotkeySection = document.createElement("div");
        var hotkeyTitle = document.createElement("div");
        hotkeyTitle.textContent = "Panel Toggle Hotkey";
        hotkeyTitle.style.cssText = "color:" + tc.textSec + ";font-size:13px;font-weight:600;margin-bottom:10px;text-transform:uppercase;letter-spacing:0.5px;";
        hotkeySection.appendChild(hotkeyTitle);

        var hotkeyInput = document.createElement("input");
        hotkeyInput.type = "text";
        hotkeyInput.readOnly = true;
        hotkeyInput.value = pendingHotkey;
        hotkeyInput.setAttribute("aria-label", "Panel toggle hotkey");
        hotkeyInput.setAttribute("placeholder", "Click and press a key\u2026");
        hotkeyInput.style.cssText = "width:100%;box-sizing:border-box;padding:10px 12px;background:" + tc.inputBg + " !important;border:2px solid " + tc.inputBorder + ";border-radius:8px;color:" + tc.inputText + " !important;font-size:14px;font-weight:500;outline:none;cursor:pointer;text-align:center;letter-spacing:0.5px;transition:border-color 0.3s ease;font-family:monospace;-webkit-text-fill-color:" + tc.inputText + " !important;opacity:1 !important;";
        hotkeyInput.onfocus = function() {
            hotkeyInput.style.borderColor = tc.inputFocus;
            hotkeyInput.value = "";
            hotkeyInput.setAttribute("placeholder", "Press any key\u2026");
        };
        hotkeyInput.onblur = function() {
            hotkeyInput.style.borderColor = tc.inputBorder;
            if (!pendingHotkey || pendingHotkey === originalHotkey) {
                hotkeyInput.value = pendingHotkey || originalHotkey;
            }
        };
        hotkeyInput.addEventListener("keydown", function(e) {
            e.preventDefault();
            e.stopPropagation();
            var key = e.key;
            var code = e.code;
            var displayKey = key;
            if (key.length === 1 && key.match(/[a-z]/i)) {
                displayKey = key.toUpperCase();
            } else if (code && code.startsWith("Key")) {
                displayKey = code.substring(3);
            } else if (code && code.startsWith("Digit")) {
                displayKey = code.substring(5);
            } else if (key === " ") {
                displayKey = "Space";
            } else if (key.startsWith("F") && key.length <= 3) {
                displayKey = key.toUpperCase();
            } else if (key === "Escape") {
                displayKey = "Escape";
            } else if (key === "Enter") {
                displayKey = "Enter";
            } else if (key === "Tab") {
                displayKey = "Tab";
            } else if (key === "Backspace") {
                displayKey = "Backspace";
            } else if (code) {
                displayKey = code;
            }
            hotkeyInput.value = displayKey;
            pendingHotkey = displayKey;
            checkDirty();
        });
        hotkeySection.appendChild(hotkeyInput);

        // === DISPLAY SECTION ===
        var displaySection = document.createElement("div");
        displaySection.style.cssText = "margin-top:18px;padding-top:14px;border-top:1px solid " + tc.sectionBorder + ";";
        var displayTitle = document.createElement("div");
        displayTitle.textContent = "Display";
        displayTitle.style.cssText = "color:" + tc.textSec + ";font-size:13px;font-weight:600;margin-bottom:10px;text-transform:uppercase;letter-spacing:0.5px;";
        displaySection.appendChild(displayTitle);

        // Theme row
        var themeRow = document.createElement("div");
        themeRow.style.cssText = "display:flex;gap:8px;margin-bottom:10px;";
        var themes = [
            { value: THEME_MODE_BLACK, label: "Black" },
            { value: THEME_MODE_GLASS, label: "Glassmorphism" }
        ];
        for (var ti = 0; ti < themes.length; ti++) {
            (function(themeOpt) {
                var themeBtn = document.createElement("button");
                themeBtn.textContent = themeOpt.label;
                themeBtn.setAttribute("type", "button");
                themeBtn.dataset.themeValue = themeOpt.value;
                var isActive = (pendingTheme === themeOpt.value);
                themeBtn.style.cssText = "flex:1;padding:8px 12px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:" + (isActive ? "600" : "400") + ";border:1px solid " + (isActive ? tc.tBtnActiveBorder : tc.tBtnInactiveBorder) + ";background:" + (isActive ? tc.tBtnActiveBg : tc.tBtnInactiveBg) + ";color:white;transition:all 0.2s ease;";
                themeBtn.onclick = function() {
                    pendingTheme = themeOpt.value;
                    var siblings = themeRow.querySelectorAll("button");
                    for (var si = 0; si < siblings.length; si++) {
                        var isA = siblings[si].dataset.themeValue === pendingTheme;
                        siblings[si].style.fontWeight = isA ? "600" : "400";
                        siblings[si].style.border = "1px solid " + (isA ? tc.tBtnActiveBorder : tc.tBtnInactiveBorder);
                        siblings[si].style.background = isA ? tc.tBtnActiveBg : tc.tBtnInactiveBg;
                    }
                    checkDirty();
                };
                themeBtn.onmouseover = function() { if (pendingTheme !== themeOpt.value) themeBtn.style.background = tc.tBtnHover; };
                themeBtn.onmouseout = function() { if (pendingTheme !== themeOpt.value) themeBtn.style.background = tc.tBtnInactiveBg; };
                themeRow.appendChild(themeBtn);
            })(themes[ti]);
        }
        displaySection.appendChild(themeRow);

        var themeHint = document.createElement("div");
        themeHint.textContent = "Theme change will apply after Save & Refresh";
        themeHint.style.cssText = "font-size:11px;color:" + tc.textMuted + ";font-style:italic;margin-bottom:6px;";
        displaySection.appendChild(themeHint);

        // === FEATURE BUTTONS SECTION (2-column grid) ===
        var btnSection = document.createElement("div");
        btnSection.style.cssText = "margin-top:18px;padding-top:14px;border-top:1px solid " + tc.sectionBorder + ";";
        var btnSectionTitle = document.createElement("div");
        btnSectionTitle.textContent = "Feature Buttons";
        btnSectionTitle.style.cssText = "color:" + tc.textSec + ";font-size:13px;font-weight:600;margin-bottom:4px;text-transform:uppercase;letter-spacing:0.5px;";
        btnSection.appendChild(btnSectionTitle);
        var btnSectionHint = document.createElement("div");
        btnSectionHint.textContent = "Drag buttons to reorder. Dropped button inserts at that cell; others shift right.";
        btnSectionHint.style.cssText = "font-size:11px;color:" + tc.textHint + ";margin-bottom:10px;font-style:italic;";
        btnSection.appendChild(btnSectionHint);

        var btnGridContainer = document.createElement("div");
        btnGridContainer.style.cssText = "max-height:480px;overflow-y:auto;border-radius:6px;background:" + tc.gridBg + ";padding:6px;";
        btnGridContainer.setAttribute("role", "grid");
        btnGridContainer.setAttribute("aria-label", "Feature button order and visibility");
        var defMap = buildPanelDefMap();
        var dragSrcPos = null;

        // --- Auto-scroll during drag ---
        var autoScrollRAF = null;
        var autoScrollSpeed = 0;
        function startAutoScroll() {
            if (autoScrollRAF) return;
            function tick() {
                if (autoScrollSpeed !== 0) {
                    btnGridContainer.scrollTop += autoScrollSpeed;
                }
                autoScrollRAF = requestAnimationFrame(tick);
            }
            autoScrollRAF = requestAnimationFrame(tick);
        }
        function stopAutoScroll() {
            if (autoScrollRAF) {
                cancelAnimationFrame(autoScrollRAF);
                autoScrollRAF = null;
            }
            autoScrollSpeed = 0;
        }
        btnGridContainer.addEventListener("dragover", function(e) {
            e.preventDefault();
            var rect = btnGridContainer.getBoundingClientRect();
            var y = e.clientY;
            var edgeZone = 40;
            if (y - rect.top < edgeZone) {
                autoScrollSpeed = -Math.max(2, Math.round((edgeZone - (y - rect.top)) / 4));
                startAutoScroll();
            } else if (rect.bottom - y < edgeZone) {
                autoScrollSpeed = Math.max(2, Math.round((edgeZone - (rect.bottom - y)) / 4));
                startAutoScroll();
            } else {
                autoScrollSpeed = 0;
            }
        });
        btnGridContainer.addEventListener("dragleave", function(e) {
            var rect = btnGridContainer.getBoundingClientRect();
            if (e.clientX < rect.left || e.clientX > rect.right || e.clientY < rect.top || e.clientY > rect.bottom) {
                stopAutoScroll();
            }
        });
        btnGridContainer.addEventListener("drop", function() { stopAutoScroll(); });
        btnGridContainer.addEventListener("dragend", function() { stopAutoScroll(); });

        var btnGrid = document.createElement("div");
        btnGrid.style.cssText = "display:grid;grid-template-columns:1fr 1fr;gap:4px;";

        // --- Insert-and-shift logic ---
        function moveButtonToPosition(fromPos, toPos) {
            if (fromPos === toPos) return;
            var sorted = pendingLayout.slice().sort(function(a, b) { return a.position - b.position; });
            var movedItem = null;
            var movedIdx = -1;
            for (var mi = 0; mi < sorted.length; mi++) {
                if (sorted[mi].position === fromPos) { movedItem = sorted[mi]; movedIdx = mi; break; }
            }
            if (!movedItem) return;
            sorted.splice(movedIdx, 1);
            var insertIdx = 0;
            for (var ii = 0; ii < sorted.length; ii++) {
                if (sorted[ii].position < toPos) insertIdx = ii + 1;
                else if (sorted[ii].position === toPos) { insertIdx = ii; break; }
            }
            if (toPos > fromPos && insertIdx > sorted.length) insertIdx = sorted.length;
            sorted.splice(insertIdx, 0, movedItem);
            for (var ri = 0; ri < sorted.length; ri++) {
                for (var pi = 0; pi < pendingLayout.length; pi++) {
                    if (pendingLayout[pi].id === sorted[ri].id) {
                        pendingLayout[pi].position = ri;
                        break;
                    }
                }
            }
        }

        function renderBtnGrid() {
            btnGrid.innerHTML = "";
            var sorted = pendingLayout.slice().sort(function(a, b) { return a.position - b.position; });
            for (var si = 0; si < sorted.length; si++) {
                (function(siLocal) {
                    var entry = sorted[siLocal];
                    var def = defMap[entry.id];
                    if (!def) return;

                    var cell = document.createElement("div");
                    cell.setAttribute("role", "gridcell");
                    cell.setAttribute("aria-label", def.label + (entry.visible ? "" : " (hidden)"));
                    cell.setAttribute("draggable", "true");
                    cell.setAttribute("tabindex", "0");
                    cell.dataset.pos = String(entry.position);
                    cell.style.cssText = "display:flex;align-items:center;gap:6px;padding:6px 8px;border-radius:5px;cursor:grab;transition:background 0.15s ease,opacity 0.15s ease,box-shadow 0.15s ease;background:" + tc.cellBg + ";opacity:" + (entry.visible ? "1" : "0.4") + ";border:1px solid transparent;min-height:36px;user-select:none;";
                    cell.onmouseover = function() { if (dragSrcPos === null) cell.style.background = tc.cellHover; };
                    cell.onmouseout = function() { if (dragSrcPos === null) cell.style.background = tc.cellBg; };

                    var posLabel = document.createElement("span");
                    posLabel.textContent = String(entry.position + 1);
                    posLabel.style.cssText = "color:rgba(255,255,255,0.35);font-size:10px;min-width:16px;text-align:center;flex-shrink:0;font-weight:600;";

                    var nameLabel = document.createElement("span");
                    nameLabel.textContent = def.label;
                    nameLabel.style.cssText = "color:white;font-size:11px;font-weight:500;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" + (entry.visible ? "" : "text-decoration:line-through;color:rgba(255,255,255,0.45);");

                    var toggleBtn = document.createElement("button");
                    toggleBtn.textContent = entry.visible ? "\u2713" : "\u2715";
                    toggleBtn.setAttribute("aria-label", (entry.visible ? "Hide " : "Show ") + def.label);
                    toggleBtn.setAttribute("type", "button");
                    toggleBtn.title = entry.visible ? "Hide" : "Show";
                    var toggleBg = entry.visible ? "rgba(107,207,127,0.35)" : "rgba(255,100,100,0.3)";
                    var toggleBorder = entry.visible ? "rgba(107,207,127,0.5)" : "rgba(255,100,100,0.5)";
                    var toggleColor = entry.visible ? "#6bcf7f" : "#ff8a8a";
                    toggleBtn.style.cssText = "background:" + toggleBg + ";border:1px solid " + toggleBorder + ";color:" + toggleColor + ";width:22px;height:22px;border-radius:4px;cursor:pointer;font-size:11px;font-weight:700;flex-shrink:0;transition:all 0.2s ease;display:flex;align-items:center;justify-content:center;padding:0;line-height:1;";
                    toggleBtn.onclick = function(e) {
                        e.stopPropagation();
                        for (var ti = 0; ti < pendingLayout.length; ti++) {
                            if (pendingLayout[ti].id === entry.id) {
                                pendingLayout[ti].visible = !pendingLayout[ti].visible;
                                break;
                            }
                        }
                        renderBtnGrid();
                        checkDirty();
                    };

                    // Drag events
                    cell.addEventListener("dragstart", function(e) {
                        dragSrcPos = entry.position;
                        e.dataTransfer.effectAllowed = "move";
                        e.dataTransfer.setData("text/plain", String(entry.position));
                        setTimeout(function() { cell.style.opacity = "0.25"; cell.style.background = tc.cellFaded; }, 0);
                    });
                    cell.addEventListener("dragend", function() {
                        cell.style.opacity = entry.visible ? "1" : "0.4";
                        cell.style.background = tc.cellBg;
                        cell.style.border = "1px solid transparent";
                        dragSrcPos = null;
                        stopAutoScroll();
                    });
                    cell.addEventListener("dragover", function(e) {
                        e.preventDefault();
                        e.dataTransfer.dropEffect = "move";
                        if (dragSrcPos !== null && dragSrcPos !== entry.position) {
                            cell.style.background = tc.cellDrag;
                            cell.style.border = "1px solid " + tc.cellDragBorder;
                        }
                    });
                    cell.addEventListener("dragleave", function() {
                        cell.style.background = tc.cellBg;
                        cell.style.border = "1px solid transparent";
                    });
                    cell.addEventListener("drop", function(e) {
                        e.preventDefault();
                        e.stopPropagation();
                        cell.style.background = tc.cellBg;
                        cell.style.border = "1px solid transparent";
                        var fromPos = parseInt(e.dataTransfer.getData("text/plain"), 10);
                        if (isNaN(fromPos) || fromPos === entry.position) return;
                        moveButtonToPosition(fromPos, entry.position);
                        renderBtnGrid();
                        checkDirty();
                    });

                    // Keyboard navigation (arrows: left/right/up/down in 2-col grid)
                    cell.addEventListener("keydown", function(e) {
                        var sorted2 = pendingLayout.slice().sort(function(a, b) { return a.position - b.position; });
                        var curIdx = -1;
                        for (var ci = 0; ci < sorted2.length; ci++) { if (sorted2[ci].id === entry.id) { curIdx = ci; break; } }
                        var targetIdx = -1;
                        if (e.key === "ArrowLeft" && curIdx > 0) { targetIdx = curIdx - 1; }
                        else if (e.key === "ArrowRight" && curIdx < sorted2.length - 1) { targetIdx = curIdx + 1; }
                        else if (e.key === "ArrowUp" && curIdx >= 2) { targetIdx = curIdx - 2; }
                        else if (e.key === "ArrowDown" && curIdx + 2 < sorted2.length) { targetIdx = curIdx + 2; }
                        if (targetIdx >= 0) {
                            e.preventDefault();
                            var swapEntry = sorted2[targetIdx];
                            var curEntry = sorted2[curIdx];
                            for (var sk = 0; sk < pendingLayout.length; sk++) {
                                if (pendingLayout[sk].id === swapEntry.id) {
                                    var tmpP = pendingLayout[sk].position;
                                    pendingLayout[sk].position = curEntry.position;
                                    for (var sk2 = 0; sk2 < pendingLayout.length; sk2++) {
                                        if (pendingLayout[sk2].id === curEntry.id) { pendingLayout[sk2].position = tmpP; }
                                    }
                                    break;
                                }
                            }
                            renderBtnGrid();
                            checkDirty();
                            var cells = btnGrid.querySelectorAll("[role='gridcell']");
                            if (cells[targetIdx]) cells[targetIdx].focus();
                        }
                    });

                    cell.appendChild(posLabel);
                    cell.appendChild(nameLabel);
                    cell.appendChild(toggleBtn);
                    btnGrid.appendChild(cell);
                })(si);
            }
        }
        renderBtnGrid();
        btnGridContainer.appendChild(btnGrid);
        btnSection.appendChild(btnGridContainer);

        // === FOOTER ===
        var modalFooter = document.createElement("div");
        modalFooter.style.cssText = "padding:12px 16px;display:flex;gap:8px;justify-content:flex-end;border-top:1px solid " + tc.sectionBorder + ";flex-shrink:0;";

        var cancelBtn = document.createElement("button");
        cancelBtn.textContent = "Cancel";
        cancelBtn.setAttribute("type", "button");
        cancelBtn.style.cssText = "background:" + tc.cancelBg + ";border:1px solid " + tc.cancelBorder + ";color:white;padding:8px 18px;border-radius:8px;cursor:pointer;font-size:13px;font-weight:500;transition:all 0.3s ease;";
        cancelBtn.onmouseover = function() { cancelBtn.style.background = tc.cancelHover; };
        cancelBtn.onmouseout = function() { cancelBtn.style.background = tc.cancelBg; };

        var saveBtn = document.createElement("button");
        saveBtn.textContent = "Save & Refresh";
        saveBtn.setAttribute("type", "button");
        saveBtn.disabled = true;
        saveBtn.style.cssText = "background:rgba(40,167,69,0.6);border:1px solid rgba(40,167,69,0.8);color:white;padding:8px 18px;border-radius:8px;cursor:not-allowed;font-size:13px;font-weight:600;transition:all 0.3s ease;opacity:0.5;";

        function updateSaveBtnState(enabled) {
            saveBtn.disabled = !enabled;
            if (enabled) {
                saveBtn.style.cursor = "pointer";
                saveBtn.style.opacity = "1";
                saveBtn.style.background = "rgba(40,167,69,0.8)";
            } else {
                saveBtn.style.cursor = "not-allowed";
                saveBtn.style.opacity = "0.5";
                saveBtn.style.background = "rgba(40,167,69,0.6)";
            }
        }

        saveBtn.onmouseover = function() {
            if (!saveBtn.disabled) saveBtn.style.background = "rgba(40,167,69,1)";
        };
        saveBtn.onmouseout = function() {
            if (!saveBtn.disabled) saveBtn.style.background = "rgba(40,167,69,0.8)";
            else saveBtn.style.background = "rgba(40,167,69,0.6)";
        };

        function checkDirty() {
            cfgHasDirty = false;
            if (pendingHotkey !== originalHotkey) cfgHasDirty = true;
            if (pendingTheme !== originalTheme) cfgHasDirty = true;
            if (JSON.stringify(pendingLayout) !== JSON.stringify(originalLayout)) cfgHasDirty = true;
            updateSaveBtnState(cfgHasDirty);
        }

        function closeModal() {
            SETTINGS_MODAL_OPEN = false;
            if (escHandler) {
                document.removeEventListener("keydown", escHandler, true);
            }
            var modal = document.getElementById("clinspark-settings-modal");
            if (modal && modal.parentNode) {
                modal.parentNode.removeChild(modal);
            }
        }

        modalClose.onclick = function() {
            log("Settings: modal closed via X");
            closeModal();
        };

        cancelBtn.onclick = function() {
            log("Settings: modal cancelled");
            closeModal();
        };

        saveBtn.onclick = function() {
            if (saveBtn.disabled) return;
            var hotkeyChanged = pendingHotkey !== originalHotkey;
            var themeChanged = pendingTheme !== originalTheme;
            var layoutChanged = JSON.stringify(pendingLayout) !== JSON.stringify(originalLayout);
            closeModal();
            if (hotkeyChanged) {
                setPanelHotkey(pendingHotkey);
                log("Settings: Hotkey saved as " + pendingHotkey);
            }
            if (themeChanged) {
                try { localStorage.setItem(STORAGE_THEME_MODE, pendingTheme); } catch(e) {}
                log("Settings: Theme saved as " + pendingTheme);
            }
            if (layoutChanged) {
                saveButtonLayout(pendingLayout);
                // Also sync old visibility map for backward compat
                var newVis = {};
                for (var vi = 0; vi < pendingLayout.length; vi++) {
                    newVis[pendingLayout[vi].id] = pendingLayout[vi].visible;
                }
                setButtonVisibility(newVis);
                log("Settings: Button layout saved");
            }
            log("Settings: Saved, refreshing");
            location.reload();
        };

        var escHandler = function(e) {
            if (e.key === "Escape" && SETTINGS_MODAL_OPEN) {
                if (document.activeElement === hotkeyInput) {
                    hotkeyInput.blur();
                    e.preventDefault();
                    e.stopPropagation();
                    return;
                }
                e.preventDefault();
                e.stopPropagation();
                log("Settings: modal closed via Escape");
                closeModal();
            }
        };
        document.addEventListener("keydown", escHandler, true);

        overlay.onclick = function(e) {
            if (e.target === overlay) {
                log("Settings: modal closed via overlay click");
                closeModal();
            }
        };

        // Assemble
        modalBody.appendChild(hotkeySection);
        modalBody.appendChild(displaySection);
        modalBody.appendChild(btnSection);

        modalFooter.appendChild(cancelBtn);
        modalFooter.appendChild(saveBtn);

        container.appendChild(modalHeader);
        container.appendChild(modalBody);
        container.appendChild(modalFooter);

        overlay.id = "clinspark-settings-modal";
        overlay.appendChild(container);
        document.body.appendChild(overlay);

        log("Settings: modal opened");
        return null;
    }

    //==========================
    // PARSE STUDY EVENT FEATURE
    //==========================
    // This section contains functions for parsing study events from the study library.
    // It extracts study event names and generates formatted output for coding use.
    //==========================

    var PARSE_STUDY_EVENT_IGNORE_KEYWORDS = [
        "subject", "screening", "ae/cm", "ae", "cm", "unscheduled", "early term",
        "early termination", "medication", "concomitant", "concommitant", "protocol",
        "adverse", "event"
    ];

    function isStudyEventPage() {
        var url = location.href.toLowerCase();
        var match1 = url.indexOf("cenexel.clinspark.com/secure/crfdesign/studylibrary/list/studyevent") !== -1;
        var match2 = url.indexOf("cenexeltest.clinspark.com/secure/crfdesign/studylibrary/list/studyevent") !== -1;
        return match1 || match2;
    }

    function parseStudyEventShouldIgnore(name) {
        var lower = name.toLowerCase();
        for (var i = 0; i < PARSE_STUDY_EVENT_IGNORE_KEYWORDS.length; i++) {
            if (lower.indexOf(PARSE_STUDY_EVENT_IGNORE_KEYWORDS[i]) !== -1) {
                return true;
            }
        }
        return false;
    }

    function parseStudyEventExtractDayNumber(name) {
        var normalized = name.replace(/\s+/g, " ").trim();
        var rangeMatch = normalized.match(/\b(?:day|d)\s*(-?\d+)\s*(?:-|to)\s*(?:day|d)?\s*(-?\d+)/i);
        if (rangeMatch) {
            var n1 = parseInt(rangeMatch[1], 10);
            var n2 = parseInt(rangeMatch[2], 10);
            if (n1 > n2) { var tmp = n1; n1 = n2; n2 = tmp; }
            return { type: "range", min: n1, max: n2, mid: Math.round((n1 + n2) / 2) };
        }
        var singleMatch = normalized.match(/\b(?:day|d)\s*(-?\d+)\b/i);
        if (singleMatch) {
            var num = parseInt(singleMatch[1], 10);
            return { type: "single", value: num };
        }
        return null;
    }

    function parseStudyEventExtractGroupLabel(name) {
        var match = name.match(/^\s*(\([^)]+\)|\[[^\]]+\])\s*/);
        if (match) {
            return match[1].trim();
        }
        return null;
    }

    function parseStudyEventExtractAffix(name) {
        var normalized = name.replace(/\s+/g, " ").trim();
        var dayMatch = normalized.match(/\b(?:day|d)\s*-?\d+(?:\s*(?:-|to)\s*(?:day|d)?\s*-?\d+)?\s*/gi);
        if (!dayMatch || dayMatch.length === 0) {
            return { baseName: name, affix: null };
        }
        var lastDayMatch = dayMatch[dayMatch.length - 1];
        var lastIdx = normalized.toLowerCase().lastIndexOf(lastDayMatch.toLowerCase());
        var afterDay = normalized.substring(lastIdx + lastDayMatch.length).trim();
        afterDay = afterDay.replace(/^[\)\]]+/, "").trim();
        if (afterDay.length > 0 && !/^\d/.test(afterDay)) {
            var baseName = normalized.substring(0, lastIdx + lastDayMatch.length).trim();
            return { baseName: baseName, affix: afterDay };
        }
        return { baseName: name, affix: null };
    }

    function parseStudyEventGetBaseName(name, affixChecked) {
        if (!affixChecked) {
            return name;
        }
        var result = parseStudyEventExtractAffix(name);
        return result.baseName;
    }

    function parseStudyEventCollectFromTable() {
        var tbody = document.getElementById("sortableTable");
        if (!tbody) {
            log("[ParseStudyEvent] sortableTable not found");
            return [];
        }
        var rows = tbody.querySelectorAll("tr[id^='se_']");
        var events = [];
        for (var i = 0; i < rows.length; i++) {
            var row = rows[i];
            var rowId = row.id;
            if (rowId === "listTableNoRecordId") continue;
            var anchor = row.querySelector("td.dragHandle a");
            if (anchor) {
                var rawName = anchor.textContent || "";
                var name = rawName.replace(/\s+/g, " ").trim();
                if (name.length > 0) {
                    events.push({ name: name, originalName: rawName.trim() });
                    log("[ParseStudyEvent] Collected: \"" + name + "\"");
                }
            }
        }
        return events;
    }

    function parseStudyEventGenerateColumn1(events) {
        var lines = [];
        for (var i = 0; i < events.length; i++) {
            lines.push("\"" + events[i].name + "\"");
        }
        return lines.join(",\n");
    }

    function parseStudyEventFindScreeningEvent(events) {
        for (var i = 0; i < events.length; i++) {
            var lower = events[i].name.toLowerCase();
            if (lower.indexOf("screen") !== -1 || lower.indexOf("scrn") !== -1) {
                return events[i].name;
            }
        }
        return null;
    }

    function parseStudyEventFindSubjectEvent(events) {
        for (var i = 0; i < events.length; i++) {
            var lower = events[i].name.toLowerCase();
            if (lower.indexOf("subject") !== -1) {
                return events[i].name;
            }
        }
        return null;
    }

    function parseStudyEventGenerateColumn2(events, affixChecked, groupChecked) {
        var lines = [];
        var screeningEvent = parseStudyEventFindScreeningEvent(events);
        var subjectEvent = parseStudyEventFindSubjectEvent(events);
        var fallbackForNeg1 = screeningEvent || subjectEvent || null;

        var processedEvents = [];
        for (var i = 0; i < events.length; i++) {
            var ev = events[i];
            var dayInfo = parseStudyEventExtractDayNumber(ev.name);
            var groupLabel = groupChecked ? parseStudyEventExtractGroupLabel(ev.name) : null;
            var affixInfo = parseStudyEventExtractAffix(ev.name);
            var baseName = affixChecked ? affixInfo.baseName : ev.name;
            var hasAffix = affixChecked && affixInfo.affix !== null && affixInfo.affix.length > 0;
            processedEvents.push({
                name: ev.name,
                baseName: baseName,
                dayInfo: dayInfo,
                dayValue: dayInfo ? (dayInfo.type === "single" ? dayInfo.value : dayInfo.max) : null,
                groupLabel: groupLabel,
                hasAffix: hasAffix,
                index: i
            });
        }

        for (var i = 0; i < processedEvents.length; i++) {
            var current = processedEvents[i];

            if (parseStudyEventShouldIgnore(current.name)) {
                log("[ParseStudyEvent] Column2 skip (ignore keyword): \"" + current.name + "\"");
                continue;
            }

            if (current.dayInfo === null) {
                log("[ParseStudyEvent] Column2 skip (no day number): \"" + current.name + "\"");
                continue;
            }

            var mappedTo = null;
            var currentDay = current.dayValue;

            if (currentDay === -1) {
                mappedTo = fallbackForNeg1;
                log("[ParseStudyEvent] Column2 \"" + current.name + "\" mapped to Screening/Subject: \"" + mappedTo + "\"");
            } else {
                if (affixChecked && current.hasAffix) {
                    for (var j = i - 1; j >= 0; j--) {
                        var prev = processedEvents[j];
                        if (parseStudyEventShouldIgnore(prev.name)) continue;
                        if (groupChecked && prev.groupLabel !== current.groupLabel) continue;
                        if (!prev.hasAffix && prev.dayValue !== null) {
                            mappedTo = prev.name;
                            log("[ParseStudyEvent] Column2 \"" + current.name + "\" (affixed) mapped to non-affixed: \"" + mappedTo + "\"");
                            break;
                        }
                    }
                }

                if (!mappedTo) {
                    var targetDay = currentDay - 1;
                    var closestPrev = null;
                    var closestDiff = Infinity;

                    for (var j = i - 1; j >= 0; j--) {
                        var prev = processedEvents[j];
                        if (parseStudyEventShouldIgnore(prev.name)) continue;
                        if (groupChecked && prev.groupLabel !== current.groupLabel) continue;
                        if (prev.dayValue === null) continue;
                        if (affixChecked && prev.hasAffix) continue;

                        if (prev.dayValue === targetDay) {
                            mappedTo = prev.name;
                            log("[ParseStudyEvent] Column2 \"" + current.name + "\" mapped to N-1: \"" + mappedTo + "\"");
                            break;
                        }

                        if (prev.dayValue < currentDay) {
                            var diff = currentDay - prev.dayValue;
                            if (diff < closestDiff) {
                                closestDiff = diff;
                                closestPrev = prev;
                            }
                        }
                    }

                    if (!mappedTo && closestPrev) {
                        mappedTo = closestPrev.name;
                        log("[ParseStudyEvent] Column2 \"" + current.name + "\" mapped to closest previous: \"" + mappedTo + "\"");
                    }

                    if (!mappedTo && groupChecked && current.groupLabel) {
                        for (var j = i - 1; j >= 0; j--) {
                            var prev = processedEvents[j];
                            if (parseStudyEventShouldIgnore(prev.name)) continue;
                            if (prev.dayValue === null) continue;
                            if (affixChecked && prev.hasAffix) continue;
                            if (prev.dayValue < currentDay) {
                                mappedTo = prev.name;
                                log("[ParseStudyEvent] Column2 \"" + current.name + "\" (group fallback) mapped to: \"" + mappedTo + "\"");
                                break;
                            }
                        }
                    }
                }
            }

            if (mappedTo) {
                lines.push("\"" + current.name + "\" : \"" + mappedTo + "\"");
            }
        }

        return lines.join(",\n");
    }

    function parseStudyEventGenerateColumn3(events) {
        var lines = [];
        for (var i = 0; i < events.length; i++) {
            var ev = events[i];
            var dayInfo = parseStudyEventExtractDayNumber(ev.name);

            if (!dayInfo) {
                log("[ParseStudyEvent] Column3 skip (no day): \"" + ev.name + "\"");
                continue;
            }

            var outputValue;
            if (dayInfo.type === "range") {
                outputValue = dayInfo.mid;
                log("[ParseStudyEvent] Column3 \"" + ev.name + "\" range mid: " + outputValue);
            } else {
                outputValue = dayInfo.value - 1;
                log("[ParseStudyEvent] Column3 \"" + ev.name + "\" day-1: " + outputValue);
            }

            lines.push("\"" + ev.name + "\" : " + outputValue);
        }
        return lines.join(",\n");
    }

    function parseStudyEventCopyToClipboard(text) {
        if (navigator.clipboard && navigator.clipboard.writeText) {
            navigator.clipboard.writeText(text).then(function() {
                log("[ParseStudyEvent] Copied to clipboard");
            }).catch(function(err) {
                log("[ParseStudyEvent] Clipboard error: " + err);
            });
        } else {
            var ta = document.createElement("textarea");
            ta.value = text;
            ta.style.position = "fixed";
            ta.style.left = "-9999px";
            document.body.appendChild(ta);
            ta.select();
            try {
                document.execCommand("copy");
                log("[ParseStudyEvent] Copied to clipboard (fallback)");
            } catch (err) {
                log("[ParseStudyEvent] Copy failed: " + err);
            }
            document.body.removeChild(ta);
        }
    }

    function parseStudyEventCreateResultsUI(events, affixChecked, groupChecked) {
        var container = document.createElement("div");
        container.style.display = "flex";
        container.style.flexDirection = "column";
        container.style.gap = "16px";
        container.style.height = "100%";

        var countDiv = document.createElement("div");
        countDiv.style.textAlign = "center";
        countDiv.style.fontSize = "16px";
        countDiv.style.fontWeight = "600";
        countDiv.style.color = "#9df";
        countDiv.style.padding = "8px";
        countDiv.style.background = "#1a1a1a";
        countDiv.style.borderRadius = "6px";
        countDiv.textContent = "Collected " + events.length + " events";
        container.appendChild(countDiv);

        var optionsDiv = document.createElement("div");
        optionsDiv.style.textAlign = "center";
        optionsDiv.style.fontSize = "12px";
        optionsDiv.style.color = "#888";
        optionsDiv.textContent = "Options: Affix=" + (affixChecked ? "Yes" : "No") + ", Group=" + (groupChecked ? "Yes" : "No");
        container.appendChild(optionsDiv);

        var columnsContainer = document.createElement("div");
        columnsContainer.style.display = "grid";
        columnsContainer.style.gridTemplateColumns = "1fr 1fr 1fr";
        columnsContainer.style.gap = "12px";
        columnsContainer.style.flex = "1";
        columnsContainer.style.minHeight = "0";
        columnsContainer.style.overflow = "hidden";

        var col1Data = parseStudyEventGenerateColumn1(events);
        var col2Data = parseStudyEventGenerateColumn2(events, affixChecked, groupChecked);
        var col3Data = parseStudyEventGenerateColumn3(events);

        function createColumn(title, data) {
            var col = document.createElement("div");
            col.style.display = "flex";
            col.style.flexDirection = "column";
            col.style.gap = "8px";
            col.style.minHeight = "0";
            col.style.overflow = "hidden";

            var header = document.createElement("div");
            header.style.display = "flex";
            header.style.justifyContent = "space-between";
            header.style.alignItems = "center";
            header.style.padding = "6px 8px";
            header.style.background = "#2a2a2a";
            header.style.borderRadius = "4px";

            var titleEl = document.createElement("span");
            titleEl.style.fontWeight = "600";
            titleEl.style.fontSize = "13px";
            titleEl.textContent = title;

            var copyBtn = document.createElement("button");
            copyBtn.textContent = "Copy";
            copyBtn.style.background = "#28a745";
            copyBtn.style.color = "#fff";
            copyBtn.style.border = "none";
            copyBtn.style.borderRadius = "4px";
            copyBtn.style.padding = "4px 10px";
            copyBtn.style.cursor = "pointer";
            copyBtn.style.fontSize = "12px";
            copyBtn.style.fontWeight = "500";
            copyBtn.addEventListener("mouseenter", function() { this.style.background = "#218838"; });
            copyBtn.addEventListener("mouseleave", function() { this.style.background = "#28a745"; });
            copyBtn.addEventListener("click", function() {
                parseStudyEventCopyToClipboard(data);
                var origText = copyBtn.textContent;
                copyBtn.textContent = "Copied!";
                copyBtn.style.background = "#17a2b8";
                setTimeout(function() {
                    copyBtn.textContent = origText;
                    copyBtn.style.background = "#28a745";
                }, 1500);
            });

            header.appendChild(titleEl);
            header.appendChild(copyBtn);
            col.appendChild(header);

            var content = document.createElement("div");
            content.style.flex = "1";
            content.style.overflow = "auto";
            content.style.background = "#1a1a1a";
            content.style.border = "1px solid #333";
            content.style.borderRadius = "4px";
            content.style.padding = "8px";
            content.style.fontSize = "12px";
            content.style.fontFamily = "monospace";
            content.style.whiteSpace = "pre-wrap";
            content.style.wordBreak = "break-word";
            content.style.color = "#e0e0e0";
            content.textContent = data;

            col.appendChild(content);
            return col;
        }

        columnsContainer.appendChild(createColumn("Study Event List", col1Data));
        columnsContainer.appendChild(createColumn("Previous Event Mapping", col2Data));
        columnsContainer.appendChild(createColumn("Day-1 Mapping", col3Data));

        container.appendChild(columnsContainer);

        return container;
    }

    function APS_ParseStudyEvent() {
        log("[ParseStudyEvent] Starting...");
        log("[ParseStudyEvent] URL check: " + location.href);

        if (!isStudyEventPage()) {
            log("[ParseStudyEvent] Not on study event page");
            showWrongPagePopup("Parse Study Event", "cenexel.clinspark.com/.../studyevent or cenexeltest.clinspark.com/.../studyevent", location.pathname);
            return;
        }

        log("[ParseStudyEvent] On valid study event page, showing options");

        var optionsContainer = document.createElement("div");
        optionsContainer.style.display = "flex";
        optionsContainer.style.flexDirection = "column";
        optionsContainer.style.gap = "20px";
        optionsContainer.style.padding = "12px";

        var checkboxesDiv = document.createElement("div");
        checkboxesDiv.style.display = "flex";
        checkboxesDiv.style.flexDirection = "column";
        checkboxesDiv.style.gap = "16px";

        function createCheckboxRow(labelText, description) {
            var row = document.createElement("label");
            row.style.display = "flex";
            row.style.alignItems = "flex-start";
            row.style.gap = "12px";
            row.style.cursor = "pointer";
            row.style.padding = "12px";
            row.style.background = "#1a1a1a";
            row.style.borderRadius = "8px";
            row.style.border = "1px solid #333";
            row.style.transition = "border-color 0.2s";
            row.addEventListener("mouseenter", function() { row.style.borderColor = "#555"; });
            row.addEventListener("mouseleave", function() { row.style.borderColor = "#333"; });

            var checkbox = document.createElement("input");
            checkbox.type = "checkbox";
            checkbox.style.width = "18px";
            checkbox.style.height = "18px";
            checkbox.style.marginTop = "2px";
            checkbox.style.cursor = "pointer";
            checkbox.style.accentColor = "#17a2b8";

            var textDiv = document.createElement("div");
            textDiv.style.display = "flex";
            textDiv.style.flexDirection = "column";
            textDiv.style.gap = "4px";

            var labelEl = document.createElement("span");
            labelEl.style.fontWeight = "600";
            labelEl.style.fontSize = "14px";
            labelEl.textContent = labelText;

            var descEl = document.createElement("span");
            descEl.style.fontSize = "12px";
            descEl.style.color = "#888";
            descEl.textContent = description;

            textDiv.appendChild(labelEl);
            textDiv.appendChild(descEl);
            row.appendChild(checkbox);
            row.appendChild(textDiv);

            return { row: row, checkbox: checkbox };
        }

        var affixCheckbox = createCheckboxRow("Affix", "Map affixed events (Predose, 1.5Hr, etc.) to previous non-affixed event");
        var groupCheckbox = createCheckboxRow("Group", "Map events within the same group label (e.g., (Sched B)) separately");

        checkboxesDiv.appendChild(affixCheckbox.row);
        checkboxesDiv.appendChild(groupCheckbox.row);
        optionsContainer.appendChild(checkboxesDiv);

        var confirmBtn = document.createElement("button");
        confirmBtn.textContent = "Confirm";
        confirmBtn.style.background = "#17a2b8";
        confirmBtn.style.color = "#fff";
        confirmBtn.style.border = "none";
        confirmBtn.style.borderRadius = "8px";
        confirmBtn.style.padding = "14px 24px";
        confirmBtn.style.cursor = "pointer";
        confirmBtn.style.fontSize = "16px";
        confirmBtn.style.fontWeight = "600";
        confirmBtn.style.transition = "background 0.2s";
        confirmBtn.addEventListener("mouseenter", function() { confirmBtn.style.background = "#138496"; });
        confirmBtn.addEventListener("mouseleave", function() { confirmBtn.style.background = "#17a2b8"; });

        optionsContainer.appendChild(confirmBtn);

        var popup = createPopup({
            title: "Parse Study Event - Options",
            content: optionsContainer,
            width: "480px",
            height: "auto"
        });

        confirmBtn.addEventListener("click", async function() {
            var affixChecked = affixCheckbox.checkbox.checked;
            var groupChecked = groupCheckbox.checkbox.checked;

            log("[ParseStudyEvent] Options chosen: Affix=" + affixChecked + ", Group=" + groupChecked);

            var loadingContainer = document.createElement("div");
            loadingContainer.style.display = "flex";
            loadingContainer.style.flexDirection = "column";
            loadingContainer.style.alignItems = "center";
            loadingContainer.style.gap = "20px";
            loadingContainer.style.padding = "40px 20px";

            var spinner = document.createElement("div");
            spinner.style.width = "48px";
            spinner.style.height = "48px";
            spinner.style.border = "4px solid #333";
            spinner.style.borderTop = "4px solid #17a2b8";
            spinner.style.borderRadius = "50%";
            spinner.style.animation = "parseStudyEventSpin 1s linear infinite";

            var style = document.createElement("style");
            style.textContent = "@keyframes parseStudyEventSpin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }";
            document.head.appendChild(style);

            var statusText = document.createElement("div");
            statusText.style.fontSize = "16px";
            statusText.style.fontWeight = "500";
            statusText.style.color = "#9df";
            statusText.textContent = "Scanning table...";

            var progressText = document.createElement("div");
            progressText.style.fontSize = "13px";
            progressText.style.color = "#888";
            progressText.textContent = "Collecting study events from sortableTable";

            loadingContainer.appendChild(spinner);
            loadingContainer.appendChild(statusText);
            loadingContainer.appendChild(progressText);

            popup.setContent(loadingContainer);

            await sleep(300);

            log("[ParseStudyEvent] Searching for sortableTable");
            var events = parseStudyEventCollectFromTable();

            if (events.length === 0) {
                log("[ParseStudyEvent] No events found");
                statusText.textContent = "No study events found";
                statusText.style.color = "#f66";
                spinner.style.display = "none";
                progressText.textContent = "Make sure the table has data loaded";
                return;
            }

            log("[ParseStudyEvent] Found " + events.length + " events, generating output");
            statusText.textContent = "Processing " + events.length + " events...";

            await sleep(200);

            var resultsUI = parseStudyEventCreateResultsUI(events, affixChecked, groupChecked);
            popup.setContent(resultsUI);

            popup.element.style.width = "1000px";
            popup.element.style.height = "600px";
            popup.element.style.maxWidth = "95%";
            popup.element.style.maxHeight = "85%";

            var rect = popup.element.getBoundingClientRect();
            popup.element.style.left = (window.innerWidth / 2) + "px";
            popup.element.style.top = (window.innerHeight / 2) + "px";
            popup.element.style.transform = "translate(-50%, -50%)";

            log("[ParseStudyEvent] Results displayed, collected " + events.length + " events");
        });
    }


